import { formatCurrencyAmount } from "@dfp/isomorphic-currency-amount";
import { getFormShape, withForm } from "@dfp/react-form";

import type { PackageTier } from "../../../../query/quoteApiTypes.ts";
import { useTT } from "../../../../useTT.ts";
import { CoverType } from "./CoverType.tsx";
import type { QuoteFormShape, RiskDef } from "./quoteForm.types.ts";
import {
  CZK_FORMAT_OPTIONS,
  deductibleValueMap,
  getPctLimitOptions,
} from "./quoteForm.utils.ts";
import { useInitQuoteForm } from "./useInitQuoteForm.ts";

const stockRisks = [
  "riskFlexa",
  "riskNatural",
  "riskFlood",
  "riskTheft",
  "riskVandal",
  "riskTheftMoney",
  "deductible",
] as const;

type StockRiskKey = (typeof stockRisks)[number];

type Props = {
  packageId: PackageTier;
};

export const StocksSection = withForm({
  defaultValues: getFormShape<QuoteFormShape>(),
  props: {} as Props,
  render: function StocksSectionInner({ form, packageId }) {
    const { tt, language } = useTT();

    const { packagesByTier } = useInitQuoteForm();
    const pkg = packagesByTier?.[packageId];
    const insObj = pkg?.stocks?.insObject?.[0];
    const stocksBaseValue = parseFloat(insObj?.riskFlexa?.value ?? "0");

    const stocksRiskConfig: Record<
      StockRiskKey,
      Omit<RiskDef, "id" | "annualCost">
    > = {
      riskFlexa: {
        payoutPeriod: "perClaim",
        payoutOptions: [
          {
            value: insObj?.riskFlexa?.value ?? "0",
            label: formatCurrencyAmount({
              ...CZK_FORMAT_OPTIONS,
              value: stocksBaseValue,
              language,
            }),
          },
        ],
        showToggle: false,
      },
      riskNatural: {
        payoutPeriod: "perClaim",
        payoutOptions: getPctLimitOptions(
          pkg?.stocks?.limits?.riskNatural ?? [],
          stocksBaseValue,
          language,
        ),
      },
      riskFlood: {
        payoutPeriod: "perClaim",
        payoutOptions: getPctLimitOptions(
          pkg?.stocks?.limits?.riskFlood ?? [],
          stocksBaseValue,
          language,
        ),
        exclusionTooltip: tt(
          "insurance.sections.quote.risks.stocks.riskFlood.exclusionTooltip",
        ),
      },
      riskTheft: {
        payoutPeriod: "perYear",
        payoutOptions: (pkg?.stocks?.limits?.riskTheft ?? []).map((l) => ({
          value: l.value,
          label: formatCurrencyAmount({
            ...CZK_FORMAT_OPTIONS,
            value: parseFloat(l.value),
            language,
          }),
        })),
      },
      riskVandal: {
        payoutPeriod: "perYear",
        payoutOptions: (pkg?.stocks?.limits?.riskVandal ?? []).map((l) => ({
          value: l.value,
          label: formatCurrencyAmount({
            ...CZK_FORMAT_OPTIONS,
            value: parseFloat(l.value),
            language,
          }),
        })),
      },
      riskTheftMoney: {
        payoutPeriod: "perYear",
        payoutOptions: (pkg?.stocks?.limits?.riskTheftMoney ?? []).map((l) => ({
          value: l.value,
          label: formatCurrencyAmount({
            ...CZK_FORMAT_OPTIONS,
            value: parseFloat(l.value),
            language,
          }),
        })),
      },
      deductible: {
        payoutPeriod: "none",
        payoutOptions: (pkg?.stocks?.limits?.deductible ?? []).map((l) => ({
          value: l.value,
          label: formatCurrencyAmount({
            ...CZK_FORMAT_OPTIONS,
            value: deductibleValueMap[l.value] ?? parseFloat(l.value),
            language,
          }),
        })),
        showAnnualCost: false,
        showToggle: false,
      },
    };

    const riskDefs = stockRisks.map<RiskDef>((key) => ({
      id: key,
      annualCost: parseFloat(
        (insObj as Record<string, { premium?: string } | undefined>)?.[key]
          ?.premium ?? "0",
      ),
      ...stocksRiskConfig[key],
    }));

    const totalYearlyCost = parseFloat(insObj?.premiumTotal ?? "0");

    return (
      <CoverType
        form={form}
        packageId={packageId}
        sectionKey="stocks"
        riskNamespace="stocks"
        title={tt("insurance.sections.quote.coverType.stocks")}
        riskDefs={riskDefs}
        totalYearlyCost={totalYearlyCost}
      />
    );
  },
});

import { formatCurrencyAmount } from "@dfp/isomorphic-currency-amount";
