const buildingsRisks = [
  "riskFlexa",
  "riskNatural",
  "riskFlood",
  "riskTheft",
  "riskVandal",
  "riskGlass",
  "deductible",
] as const;

type BuildingsRiskKey = (typeof buildingsRisks)[number];

type Props = {
  packageId: PackageTier;
  addressIndex: number;
  addressLabel: string;
};

export const BuildingsSection = withForm({
  defaultValues: getFormShape<QuoteFormShape>(),
  props: {} as Props,
  render: function BuildingsSectionInner({
    form,
    packageId,
    addressIndex,
    addressLabel,
  }) {
    const { tt, language } = useTT();
    const { packagesByTier } = useInitQuoteForm();
    const pkg = packagesByTier?.[packageId];
    const insObj = pkg?.buildings?.insObject?.[addressIndex];
    const sectionKey = `buildings_${addressIndex}` as const;

    const allBuildingValue = insObj?.riskFlexa?.value ?? "0";
    const buildingsBaseValue = parseFloat(allBuildingValue);

    const flexaOption = {
      value: allBuildingValue,
      label: formatCurrencyAmount({
        ...CZK_FORMAT_OPTIONS,
        value: buildingsBaseValue,
        language,
      }),
    };

    const buildingsRiskConfig: Record<
      BuildingsRiskKey,
      Omit<RiskDef, "id" | "annualCost">
    > = {
      riskFlexa: {
        payoutPeriod: "perClaim",
        payoutOptions: [flexaOption],
        showToggle: false,
      },
      riskNatural: {
        payoutPeriod: "perClaim",
        payoutOptions: getPctLimitOptions(
          pkg?.buildings?.limits?.riskNatural ?? [],
          buildingsBaseValue,
          language,
        ),
      },
      riskFlood: {
        payoutPeriod: "perClaim",
        payoutOptions: getPctLimitOptions(
          pkg?.buildings?.limits?.riskFlood ?? [],
          buildingsBaseValue,
          language,
        ),
      },
      riskTheft: {
        payoutPeriod: "perYear",
        payoutOptions: (pkg?.buildings?.limits?.riskTheft ?? []).map((l) => ({
          value: l.value,
          label: formatCurrencyAmount({
            ...CZK_FORMAT_OPTIONS,
            value: parseFloat(l.value),
            language,
          }),
        })),
      },
      riskVandal: {
        payoutPeriod: "perYear",
        payoutOptions: (pkg?.buildings?.limits?.riskVandal ?? []).map((l) => ({
          value: l.value,
          label: formatCurrencyAmount({
            ...CZK_FORMAT_OPTIONS,
            value: parseFloat(l.value),
            language,
          }),
        })),
      },
      riskGlass: {
        payoutPeriod: "perYear",
        payoutOptions: (pkg?.buildings?.limits?.riskGlass ?? []).map((l) => ({
          value: l.value,
          label: formatCurrencyAmount({
            ...CZK_FORMAT_OPTIONS,
            value: parseFloat(l.value),
            language,
          }),
        })),
      },
      deductible: {
        payoutPeriod: "none",
        payoutOptions: (pkg?.buildings?.limits?.deductible ?? []).map(
          (limit) => ({
            value: limit.value,
            label: formatCurrencyAmount({
              ...CZK_FORMAT_OPTIONS,
              value: deductibleValueMap[limit.value] ?? parseFloat(limit.value),
              language,
            }),
          }),
        ),
        showAnnualCost: false,
        showToggle: false,
      },
    };

    const riskDefs = buildingsRisks.map<RiskDef>((key) => ({
      id: key,
      annualCost: parseFloat(
        (insObj as Record<string, { premium?: string } | undefined>)?.[key]
          ?.premium ?? "0",
      ),
      ...buildingsRiskConfig[key],
