const engineryRisks = [
  "riskFlexa",
  "riskNatural",
  "riskFlood",
  "riskTheft",
  "riskVandal",
  "deductible",
  "riskSpecial",
  "deductibleSpecial",
] as const;

type EngineryRiskKey = (typeof engineryRisks)[number];

type Props = {
