    > = {
      riskFlexa: {
        payoutPeriod: "perClaim",
        payoutOptions: insObj?.riskFlexa?.value
          ? [
              {
                value: insObj.riskFlexa.value,
                label: formatCurrencyAmount({
                  ...CZK_FORMAT_OPTIONS,
                  value: engineryBaseValue,
                  language,
                }),
              },
            ]
          : [],
        showToggle: false,
      },
      riskNatural: {
        payoutPeriod: "perClaim",
        payoutOptions: getPctLimitOptions(
          pkg?.enginery?.limits?.riskNatural ?? [],
          engineryBaseValue,
