        ),
      },
      riskFlood: {
        payoutPeriod: "perClaim",
        payoutOptions: getPctLimitOptions(
          pkg?.enginery?.limits?.riskFlood ?? [],
          engineryBaseValue,
          language,
        ),
        exclusionTooltip: tt(
          "insurance.sections.quote.risks.enginery.riskFlood.exclusionTooltip",
        ),
      },
      riskTheft: {
        payoutPeriod: "perYear",
        payoutOptions: (pkg?.enginery?.limits?.riskTheft ?? []).map(
          (limit) => ({
            value: limit.value,
            label: formatCurrencyAmount({
              ...CZK_FORMAT_OPTIONS,
              value: parseFloat(limit.value),
              language,
            }),
          }),
        ),
      },
      riskVandal: {
        payoutPeriod: "perYear",
        payoutOptions: (pkg?.enginery?.limits?.riskVandal ?? []).map(
          (limit) => ({
            value: limit.value,
            label: formatCurrencyAmount({
              ...CZK_FORMAT_OPTIONS,
              value: parseFloat(limit.value),
              language,
            }),
          }),
        ),
      },
      deductible: {
        payoutPeriod: "none",
        payoutOptions: (pkg?.enginery?.limits?.deductible ?? []).map(
          (limit) => ({
            value: limit.value,
            label: formatCurrencyAmount({
              ...CZK_FORMAT_OPTIONS,
              value: deductibleValueMap[limit.value] ?? parseFloat(limit.value),
              language,
            }),
          }),
        ),
        showAnnualCost: false,
        showToggle: false,
      },
      riskSpecial: {
        payoutPeriod: "perClaim",
        payoutOptions: getPctLimitOptions(
          pkg?.enginery?.limits?.riskSpecial ?? [],
          engineryBaseValue,
          language,
        ),
      },
      deductibleSpecial: {
        payoutPeriod: "none",
        payoutOptions: (pkg?.enginery?.limits?.deductibleSpecial ?? [])
          .filter((limit) => limit.value !== "1")
          .map((limit) => ({
            value: limit.value,
            label: formatCurrencyAmount({
              ...CZK_FORMAT_OPTIONS,
              value: deductibleValueMap[limit.value] ?? parseFloat(limit.value),
