import { Card, CardHeader, Stack } from "@mui/material";

import { businessLiabilityInsuranceEnum } from "@dfp/isomorphic-enums";
import { CardContent } from "@dfp/react-components";
import { useEnum } from "@dfp/react-enums";
import { useAppForm } from "@dfp/react-form";
import { validateRequired } from "@dfp/react-form";

import { useTT } from "../../../../useTT.ts";
import type { LiabilityFormShape } from "./liabilityForm.types.ts";

type Props = {
  defaultValues: LiabilityFormShape;
  onSubmit: (values: LiabilityFormShape) => void;
};

export function LiabilityForm({ defaultValues, onSubmit }: Props) {
  const { tt } = useTT();
  const { enumTranslatedOptions } = useEnum(businessLiabilityInsuranceEnum);

  const coverageOptions = enumTranslatedOptions.map((option) => ({
    label: option.label,
    value: option.value,
  }));

  const form = useAppForm({
    defaultValues,
    onSubmit: async (values) => {
      await onSubmit(values.value);
    },
  });

  return (
    <form
      onSubmit={(event) => {
        event.preventDefault();
        event.stopPropagation();
        form.handleSubmit();
      }}
    >
      <form.AppForm>
        <Stack sx={{ gap: 4 }}>
          <Card>
            <CardHeader
              title={tt("insurance.sections.coverage.liabilityForm.title")}
            />
            <CardContent>
              <Stack
                sx={{
                  gap: 2,
                  p: 3,
                }}
              >
                <form.AppField
                  name="coverage"
                  validators={validateRequired()}
                  children={(field) => (
                    <field.Radio
                      options={coverageOptions}
                      label={tt(
                        "insurance.sections.coverage.liabilityForm.coverage",
                      )}
                      required
                    />
                  )}
                />
              </Stack>
            </CardContent>
          </Card>
          <form.Submit disabledOnPristine={false}>
            {tt("insurance.buttonSubmit")}
          </form.Submit>
        </Stack>
      </form.AppForm>
    </form>
  );
}

