import { useTT } from "../../../useTT.ts";
import {
  type CompanyDetailsFormShape,
  useCompanyDetailsForm,
} from "./useCompanyDetailsForm.ts";

type ContactPersonOption = {
  value: string;
  label: string;
  documentId: string;
  entityId: string;
};

type CompanyDetailsFormProps = {
  defaultValues: CompanyDetailsFormShape;
  onSubmit: (values: CompanyDetailsFormShape) => Promise<void>;
};

export function CompanyDetailsForm({
  defaultValues,
  onSubmit,
}: CompanyDetailsFormProps) {
  const { form, companyOptions, selectedCompany } = useCompanyDetailsForm({
    defaultValues,
    onSubmit,
  });
  const { tt } = useTT();

  const companyDocumentId = selectedCompany?.masterRoleRef?.documentId;

  const { data: contactPersonData } = useGetFlowpayCreditContactPersons(
    companyDocumentId,
    selectedCompany?.masterRoleRef?.entityId,
  );

  const contactPersonOptions = useMemo<ContactPersonOption[]>(() => {
    if (!contactPersonData?.documentList) return [];

    return contactPersonData.documentList
      .filter((person) => person.documentHeader.documentType === "LivePerson")
      .map((person) => {
        const doc = person as typeof person & {
          partyBasicInfo?: {
            entityHeader?: { entityId?: string };
          };
          roles?: {
            returnedItems?: Array<{
              entityData?: {
                personBasicInfo?: {
                  entityData?: { firstName?: string; surname?: string };
                };
                roleBasicInfo?: {
                  entityData?: {
                    masterRoleRef?: { documentId?: string };
                  };
                };
              };
            }>;
          };
        };

        const role = doc.roles?.returnedItems?.find(
          (r) =>
            r.entityData?.roleBasicInfo?.entityData?.masterRoleRef
              ?.documentId === companyDocumentId,
        );

        const firstName =
          role?.entityData?.personBasicInfo?.entityData?.firstName ?? "";
        const surname =
          role?.entityData?.personBasicInfo?.entityData?.surname ?? "";
        const fullName = [firstName, surname].filter(Boolean).join(" ");

        const entityId =
          doc.partyBasicInfo?.entityHeader?.entityId ??
          person.documentHeader.id;

        return {
          value: person.documentHeader.id,
          label: fullName || person.documentHeader.id,
          documentId: person.documentHeader.id,
          entityId,
        };
      });
  }, [contactPersonData, companyDocumentId]);

  return (
    <form
      onSubmit={(event) => {
        event.preventDefault();
        event.stopPropagation();
        form.handleSubmit();
      }}
    >
      <form.AppForm>
        <Stack sx={{ gap: 4 }}>
          <Card>
            <CardHeader title={tt("flowpayCredit.companyDetails.title")} />
            <CardContent>
              <Stack sx={{ gap: 3, p: 3 }}>
                <Typography variant="body2">
                  {tt("flowpayCredit.companyDetails.subtitle")}
                </Typography>
                <Stack sx={{ gap: 2 }}>
                  <form.AppField
                    name="companyId"
                    validators={{
                      onSubmit: ({ value }) =>
                        value
                          ? false
                          : tt("flowpayCredit.companyDetails.companyRequired"),
                    }}
                  >
                    {(field) => (
                      <field.Autocomplete
                        required
                        label={tt("flowpayCredit.companyDetails.companyLabel")}
                        options={companyOptions}
                      />
                    )}
                  </form.AppField>
                  <form.AppField
                    name="contactPersonId"
                    validators={{
                      onSubmit: ({ value }) =>
                        value
                          ? false
                          : tt(
                              "flowpayCredit.companyDetails.contactPersonRequired",
                            ),
                    }}
                  >
                    {(field) => {
                      const selectedOption =
                        contactPersonOptions.find(
                          (o) => o.value === field.state.value,
                        ) ?? null;

                      return (
                        <Stack sx={{ gap: 0.5 }}>
                          <Typography
                            variant="body1"
                            sx={{ color: "text.secondary" }}
                          >
                            {tt(
                              "flowpayCredit.companyDetails.contactPersonLabel",
                            )}
                          </Typography>
                          <Autocomplete
                            value={selectedOption}
                            onChange={(_, newValue) =>
                              field.handleChange(newValue?.value ?? "")
                            }
                            onBlur={field.handleBlur}
                            options={contactPersonOptions}
                            getOptionLabel={(option) => option.label}
                            getOptionKey={(option) => option.value}
                            fullWidth
                            renderOption={(props, option) => (
                              <li {...props} key={option.value}>
                                <Stack
                                  direction="row"
                                  sx={{ alignItems: "center", gap: 1.5 }}
                                >
                                  <UserAvatar
                                    name={option.label}
                                    sx={{
                                      width: 24,
                                      height: 24,
                                      fontSize: "0.7rem",
                                      flexShrink: 0,
                                    }}
                                  />
                                  {option.label}
                                </Stack>
                              </li>
                            )}
                            renderInput={(params) => (
                              <TextField
                                {...params}
                                error={field.state.meta.errors.length > 0}
                                helperText={field.state.meta.errors[0]}
                                slotProps={{
                                  input: {
                                    ...params.InputProps,
                                    startAdornment: selectedOption ? (
                                      <InputAdornment
                                        position="start"
                                        sx={{ ml: 1 }}
                                      >
                                        <UserAvatar
                                          name={selectedOption.label}
                                          sx={{
                                            width: 24,
                                            height: 24,
                                            fontSize: "0.7rem",
                                          }}
                                        />
                                      </InputAdornment>
                                    ) : undefined,
                                  },
                                }}
                              />
                            )}
                          />
                        </Stack>
                      );
                    }}
                  </form.AppField>
                </Stack>

                <Divider sx={{ mx: -3 }} />
                <ListItemWithAvatar
                  avatar={
                    <Box
                      component="img"
                      src={flowpay}
                      alt="Flowpay"
                      sx={{
                        width: 48,
                        height: 48,
                        borderRadius: "20px",
                        objectFit: "contain",
                      }}
                    />
                  }
                  title={tt("flowpayCredit.companyDetails.providerTitle")}
                  text={tt("flowpayCredit.companyDetails.providerDescription")}
                />
                <ListItemWithAvatar
                  avatar={<IconCheck />}
                  title={tt("flowpayCredit.companyDetails.feature1Title")}
                  text={tt("flowpayCredit.companyDetails.feature1Description")}
                />
                <ListItemWithAvatar
                  avatar={<IconCheck />}
                  title={tt("flowpayCredit.companyDetails.feature2Title")}
                  text={tt("flowpayCredit.companyDetails.feature2Description")}
                />
                <ListItemWithAvatar
                  avatar={<IconCheck />}
                  title={tt("flowpayCredit.companyDetails.feature3Title")}
                  text={tt("flowpayCredit.companyDetails.feature3Description")}
                />
