import {
  BankAccountAssignmentTable,
  isPreviouslyAssignedAccount,
} from "@dfp/bw-react-bank-account-assignment";
import { useExpiredBankConnectionState } from "@dfp/bw-react-expired-bank-connections";
import { useCommonTranslation } from "@dfp/react-common-translation";
import {
  AppDialog,
  AppDialogContent,
  AppDialogHeader,
  DIALOG_MAX_WIDTH,
  LoadingIndicator,
} from "@dfp/react-components";
import { useCompanyValidation } from "@dfp/react-utils";

import { useTT } from "../../useTT.ts";

export function AccountsReconnectHandler() {
  const { tt } = useTT();
  const { commonTT } = useCommonTranslation();

  const {
    accountsForAssignment,
    handleAssignmentComplete,
    handleCancelAssignment,
    isPendingAuthorizeExpiredAccounts,
    isLoadingFreshClientAccounts,
    freshAccountsDocumentId,
  } = useExpiredBankConnectionState();

  const {
    validationErrors,
    filteredValidationErrors,
    handleCompanyChange,
    validateCompanySelection,
    setCheckedAccountIds,
  } = useCompanyValidation();

  const [previouslyAssignedAccounts, newAccounts] = useMemo(
    () => partition(accountsForAssignment, isPreviouslyAssignedAccount),
    [accountsForAssignment],
  );

  const hasAccounts = accountsForAssignment.length > 0;
  const hasNewAccounts = newAccounts.length > 0;
  const hasPreviouslyAssignedAccounts = previouslyAssignedAccounts.length > 0;

  const handleConfirm = () => {
    if (!validateCompanySelection(newAccounts)) {
      return;
    }
    handleAssignmentComplete();
  };

  if (!hasAccounts) {
    return null;
  }

  return (
    <AppDialog
      open={hasAccounts}
      onClose={handleCancelAssignment}
      maxWidth={DIALOG_MAX_WIDTH}
    >
      <AppDialogHeader>
        {tt("reconnect.dialogTitle", {
          count: accountsForAssignment.length,
        })}
      </AppDialogHeader>
      <AppDialogContent sx={{ pb: 3 }}>
        <Typography
          gutterBottom
          sx={{
            marginBottom: {
              xs: 2,
              sm: 4,
            },
            marginTop: {
              xs: 1,
              sm: 1,
            },
          }}
        >
          {tt("reconnect.dialogDescription")}
        </Typography>
        <Stack sx={{ gap: 3 }}>
          {hasNewAccounts && (
            <Stack sx={{ gap: 3 }}>
              <Typography variant="body2" sx={{ fontWeight: 600 }}>
                {tt("reconnect.newAccountsSection", {
                  count: newAccounts.length,
                })}
              </Typography>
              <BankAccountAssignmentTable
                accounts={newAccounts}
                isLoading={isLoadingFreshClientAccounts}
                documentId={freshAccountsDocumentId ?? ""}
                validationErrors={validationErrors}
                onCompanyChange={handleCompanyChange}
                onSelectedAccountsChange={setCheckedAccountIds}
              />
            </Stack>
          )}
          {hasPreviouslyAssignedAccounts && (
            <Stack sx={{ gap: 3 }}>
              <Typography variant="body2" sx={{ fontWeight: 600 }}>
                {tt("reconnect.alreadyConnectedSection", {
                  count: previouslyAssignedAccounts.length,
                })}
              </Typography>
              <BankAccountAssignmentTable
                accounts={previouslyAssignedAccounts}
                isLoading={false}
                documentId={freshAccountsDocumentId ?? ""}
                isReadOnly
                isFaded
              />
            </Stack>
          )}
        </Stack>
        {filteredValidationErrors.length > 0 && (
          <Typography
            variant="body1"
            sx={{
              textAlign: "right",
              fontWeight: 400,
              color: "error.main",
              mt: 2.5,
            }}
          >
            {tt("reconnect.warningSelectCompany")}
          </Typography>
        )}
        <Box
          sx={{
            display: "flex",
            gap: 2,
            justifyContent: "space-between",
            alignItems: "center",
            marginTop: 4,
          }}
        >
          <Button color="secondary" onClick={handleCancelAssignment}>
            {commonTT("Button.cancel")}
          </Button>
          <Button
            variant="contained"
            color="primary"
            onClick={handleConfirm}
            disabled={isPendingAuthorizeExpiredAccounts}
            loading={isPendingAuthorizeExpiredAccounts}
            loadingPosition="center"
            loadingIndicator={<LoadingIndicator />}
            sx={{
              minWidth: "190px",
            }}
          >
            {commonTT("Button.confirm")}
          </Button>
        </Box>
      </AppDialogContent>
    </AppDialog>
  );
}

