import { useOpenRevokeInvitationDialog } from "../../revokeInvitationDialog/useOpenRevokeInvitationDialog.tsx";

type Props = {
  data: RevokeInvitationData;
};

export function RevokeInvitationActionItem({ data }: Props) {
  const { tt } = useTT();
  const navigate = useNavigate();
  const queryClient = useQueryClient();
  const { close: closeDropdown } = useDropdownClose();
  const openRevokeDialog = useOpenRevokeInvitationDialog();

  const handleRevokeSuccess = async () => {
    await queryClient.invalidateQueries({
      queryKey: queryKeys.invitation(data.invitationId),
    });

    await navigate(
      makeRoute(pathRoutes.companySettingsTeam, {
        companyId: data.companyId,
      }),
    );
  };

  return (
    <ListItem disablePadding>
      <ListItemButton
        onClick={() => {
          closeDropdown();
          openRevokeDialog(data, handleRevokeSuccess);
        }}
        sx={{
          color: "error.main",
          "& .MuiListItemIcon-root": {
            color: "error.main",
          },
          "&:hover": {
            backgroundColor: "errorSecondary.main",
          },
        }}
      >
        <ListItemIcon>
          <IconTrash01 />
        </ListItemIcon>
        <ListItemText
          slotProps={{
            primary: {
              variant: "body2",
              sx: { fontWeight: 600 },
              color: "errorSecondary.contrastText",
            },
          }}
        >
          {tt("revokeInvitation")}
        </ListItemText>
      </ListItemButton>
    </ListItem>
  );
}

