import { Alert } from "@mui/material";
import { isNil } from "ramda";

import {
  ContractPageWrapper,
  StepperContentSkeleton,
} from "@dfp/bw-react-frame-contract-stepper-layout";

import {
  useCreateBusinessInsuranceEntity,
  useGetBusinessInsurance,
  useUpdateBusinessInsuranceEntity,
} from "../../query/index.ts";
import { useTT } from "../../useTT.ts";
import { useCoverageNavigation } from "./components/index.ts";
import { LiabilityForm } from "./components/liabilityForm/index.ts";
import type { LiabilityFormShape } from "./components/liabilityForm/index.ts";

export function BusinessInsuranceLiabilityPage() {
  const { tt } = useTT();
  const { data: contract, isLoading, isError } = useGetBusinessInsurance();
  const { handleCoverageNavigation } = useCoverageNavigation("liability");
  const { mutateAsync: updateEntity } = useUpdateBusinessInsuranceEntity({
    onSuccess: handleCoverageNavigation,
  });
  const { mutateAsync: createEntity } = useCreateBusinessInsuranceEntity({
    onSuccess: handleCoverageNavigation,
  });

  if (isLoading) {
    return <StepperContentSkeleton />;
  }

  if (isError || !contract) {
    return (
      <ContractPageWrapper>
        <Alert severity="error">
          {tt("insurance.sections.coverage.liabilityForm.error")}
        </Alert>
      </ContractPageWrapper>
    );
  }

  async function onSubmit(values: LiabilityFormShape) {
    if (isNil(values.coverage) || !contract) return;

    const entityData = contract?.businessLiabilityInsuranceCoverage?.entityData;

    const businessLiabilityInsuranceCoverage = {
      entityData: { coverage: values.coverage },
    };

    if (!entityData) {
      await createEntity({
        contract,
        createEntity: {
          businessLiabilityInsuranceCoverage,
        },
      });
    } else {
      await updateEntity({
        contract,
        updateEntity: {
          businessLiabilityInsuranceCoverage,
        },
      });
    }
  }

  const defaultValues: LiabilityFormShape = {
    coverage:
      contract?.businessLiabilityInsuranceCoverage?.entityData?.coverage ??
      null,
  };

  return (
    <ContractPageWrapper>
      <LiabilityForm onSubmit={onSubmit} defaultValues={defaultValues} />
    </ContractPageWrapper>
  );
}

