import { useStore } from "@tanstack/react-form";

import { useCompanyList } from "@dfp/bw-react-api-party";
import { useAppForm } from "@dfp/react-form";

export type CompanyDetailsFormShape = {
  companyId: string;
  contactPersonId: string;
};

type Props = {
  defaultValues: CompanyDetailsFormShape;
  onSubmit: (values: CompanyDetailsFormShape) => Promise<void>;
};

export function useCompanyDetailsForm({ defaultValues, onSubmit }: Props) {
  const companies = useCompanyList();

  const form = useAppForm({
    defaultValues,
    onSubmit: async (values) => {
      await onSubmit(values.value);
    },
  });

  const companyOptions = companies
    ? companies
        .filter(
          (company) =>
            company?.masterRoleRef?.documentId &&
            company?.masterRoleDisplayInfo?.roleName,
        )
        .map((company) => ({
          value: company?.masterRoleRef?.documentId ?? "",
          label: company?.masterRoleDisplayInfo?.roleName ?? "",
        }))
    : [];

  const selectedCompanyId = useStore(
    form.store,
    (state) => state.values.companyId,
  );

  const selectedCompany = companies?.find(
    (company) => company?.masterRoleRef?.documentId === selectedCompanyId,
  );

  return {
    form,
    companyOptions,
    selectedCompany,
  };
}

