import { useCallback, useMemo } from "react";

import { useUserContext } from "../../useUserContext.ts";
import type { EntitlementId, FeatureId, FeatureItem } from "./types.ts";

/**
 * Aggregates features from ALL company roles and returns true if ANY role
 * grants the requested feature. Designed for global routes (Dashboard,
 * Transactions, Contacts) that live outside `CompanyRouteContextProvider`
 * and therefore have no single company context to check against.
 *
 * Returns `{ hasFeature }` with the same signature as `useFeatureGuard`:
 * - `hasFeature(featureId)` — visibility check (feature exists in any role)
 * - `hasFeature(featureId, entitlementId)` — interactivity check
 *
 * For company-scoped checks, use `useFeatureGuard()` or `useCompanyFeatures()`.
 */
export function useAnyCompanyFeature() {
  const { roles } = useUserContext();

  const allFeatures = useMemo(() => {
    if (!roles?.length) return [];

    return roles.reduce<FeatureItem[]>((result, role) => {
      if (role.features) {
        result.push(...role.features);
      }
      return result;
    }, []);
  }, [roles]);

  const hasFeature = useCallback(
    (featureId: FeatureId, entitlementId?: EntitlementId) => {
      const matchingFeatures = allFeatures.filter(
        (featureItem) => featureItem.featureId === featureId,
      );

      if (matchingFeatures.length === 0) return false;
      if (!entitlementId) return true;

      return matchingFeatures.some((feature) =>
        feature.entitlements.some(
          (entitlement) => entitlement.entitlementId === entitlementId,
        ),
      );
    },
    [allFeatures],
  );

  return { hasFeature };
}

import { useCallback } from "react";

import type { EntitlementId, FeatureId, FeatureItem } from "./types.ts";

/**
 * Shared hook that creates a memoized `hasFeature` checker from a features array.
 * Not exported publicly — used internally by `useFeatureGuard` and `useCompanyFeatures`.
 */
export function useHasFeature(features: FeatureItem[]) {
  return useCallback(
    (featureId: FeatureId, entitlementId?: EntitlementId) => {
      const matchingFeatures = features.filter(
        (featureItem) => featureItem.featureId === featureId,
      );

      if (matchingFeatures.length === 0) return false;
      if (!entitlementId) return true;

      return matchingFeatures.some((feature) =>
        feature.entitlements.some(
          (entitlement) => entitlement.entitlementId === entitlementId,
        ),
      );
    },
    [features],
  );
}

