import {
  Autocomplete,
  Card,
  CardHeader,
  Divider,
  InputAdornment,
  Stack,
  TextField,
  Typography,
} from "@mui/material";
import type { MutableRefObject } from "react";
import { useEffect } from "react";

import {
  CardContent,
  ListItemWithAvatar,
  UserAvatar,
} from "@dfp/react-components";
import { IconCheck } from "@dfp/react-icons";

import bibby from "../../../assets/companies/bibby.png";
import { useTT } from "../../../useTT.ts";
import {
  type CompanyDetailsFormShape,
  useCompanyDetailsForm,
} from "./useCompanyDetailsForm.ts";
import {
  type ContactPersonOption,
  useContactPersonList,
} from "./useContactPersonList.ts";

type Props = {
  defaultValues: CompanyDetailsFormShape;
  onSubmit: (values: CompanyDetailsFormShape) => Promise<void>;
  contactPersonOptionsRef: MutableRefObject<ContactPersonOption[]>;
};

export function CompanyDetailsForm({
  defaultValues,
  onSubmit,
  contactPersonOptionsRef,
}: Props) {
  const { form, companyOptions, selectedCompany } = useCompanyDetailsForm({
    defaultValues,
    onSubmit,
  });
  const { tt } = useTT();

  const { options: contactPersonOptions } = useContactPersonList(
    selectedCompany?.masterRoleRef?.documentId,
    selectedCompany?.masterRoleRef?.entityId,
  );

  useEffect(() => {
    contactPersonOptionsRef.current = contactPersonOptions;
  }, [contactPersonOptions, contactPersonOptionsRef]);

  return (
    <form
      onSubmit={(event) => {
        event.preventDefault();
        event.stopPropagation();
        form.handleSubmit();
      }}
    >
      <form.AppForm>
        <Stack sx={{ gap: 4 }}>
          <Card>
            <CardHeader title={tt("factoring.companyDetails.title")} />
            <Divider />
            <CardContent>
              <Stack sx={{ gap: 3, p: 3 }}>
                <Typography variant="body2">
                  {tt("factoring.companyDetails.subtitle")}
                </Typography>
                <Stack sx={{ gap: 2 }}>
                  <form.AppField
                    name="companyId"
                    validators={{
                      onSubmit: ({ value }) =>
                        value
                          ? false
                          : tt("factoring.companyDetails.companyRequired"),
                    }}
                  >
                    {(field) => (
                      <field.Autocomplete
                        required
                        label={tt("factoring.companyDetails.companyLabel")}
                        options={companyOptions}
                      />
                    )}
                  </form.AppField>
                  <form.AppField
                    name="contactPersonId"
                    validators={{
                      onSubmit: ({ value }) =>
                        value
                          ? false
                          : tt(
                              "factoring.companyDetails.contactPersonRequired",
                            ),
                    }}
                  >
                    {(field) => {
                      const selectedOption =
                        contactPersonOptions.find(
                          (o) => o.value === field.state.value,
                        ) ?? null;

                      return (
                        <Stack sx={{ gap: 0.5 }}>
                          <Typography
                            variant="body1"
                            sx={{ color: "text.secondary" }}
                          >
                            {tt("factoring.companyDetails.contactPersonLabel")}
                          </Typography>
                          <Autocomplete
                            value={selectedOption}
                            onChange={(_, newValue) =>
                              field.handleChange(newValue?.value ?? "")
                            }
                            onBlur={field.handleBlur}
                            options={contactPersonOptions}
                            getOptionLabel={(option) => option.label}
                            getOptionKey={(option) => option.value}
                            fullWidth
                            renderOption={(props, option) => (
                              <li {...props} key={option.value}>
                                <Stack
                                  direction="row"
                                  sx={{ alignItems: "center", gap: 1.5 }}
                                >
                                  <UserAvatar
                                    name={option.label}
                                    sx={{
                                      width: 24,
                                      height: 24,
                                      fontSize: "0.7rem",
                                      flexShrink: 0,
                                    }}
                                  />
                                  {option.label}
                                </Stack>
                              </li>
                            )}
                            renderInput={(params) => (
                              <TextField
                                {...params}
                                error={field.state.meta.errors.length > 0}
                                helperText={field.state.meta.errors[0]}
                                slotProps={{
                                  input: {
                                    ...params.InputProps,
                                    startAdornment: selectedOption ? (
                                      <InputAdornment
                                        position="start"
                                        sx={{ ml: 1 }}
                                      >
                                        <UserAvatar
                                          name={selectedOption.label}
                                          sx={{
                                            width: 24,
                                            height: 24,
                                            fontSize: "0.7rem",
                                          }}
                                        />
                                      </InputAdornment>
                                    ) : undefined,
                                  },
                                }}
                              />
                            )}
                          />
                        </Stack>
                      );
                    }}
                  </form.AppField>
                </Stack>

                <Divider sx={{ mx: -3 }} />
                <ListItemWithAvatar
                  avatar={
                    <img
                      src={bibby}
                      alt="Bibby Financial Services"
                      style={{
                        width: 48,
                        height: 48,
                        borderRadius: 20,
                        objectFit: "contain",
                      }}
                    />
                  }
                  title={tt("factoring.companyDetails.providerTitle")}
                  text={tt("factoring.companyDetails.providerDescription")}
                />
                <ListItemWithAvatar
                  avatar={<IconCheck />}
                  title={tt("factoring.companyDetails.feature1Title")}
                  text={tt("factoring.companyDetails.feature1Description")}
                />
                <ListItemWithAvatar
                  avatar={<IconCheck />}
                  title={tt("factoring.companyDetails.feature2Title")}
                  text={tt("factoring.companyDetails.feature2Description")}
                />
                <ListItemWithAvatar
                  avatar={<IconCheck />}
                  title={tt("factoring.companyDetails.feature3Title")}
                  text={tt("factoring.companyDetails.feature3Description")}
                />
              </Stack>
            </CardContent>
          </Card>
          <form.Submit disabledOnPristine={false}>
            {tt("factoring.buttonContinue")}
          </form.Submit>
        </Stack>
      </form.AppForm>
    </form>
  );
}

import {
  Autocomplete,
  Box,
  Card,
  CardHeader,
  Divider,
  InputAdornment,
  Stack,
  TextField,
  Typography,
} from "@mui/material";
import { useMemo } from "react";

import {
  CardContent,
  ListItemWithAvatar,
  UserAvatar,
} from "@dfp/react-components";
import { IconCheck } from "@dfp/react-icons";

import flowpay from "../../../assets/companies/flowpay.png";
import { useGetFlowpayCreditContactPersons } from "../../../query/index.ts";
import { useTT } from "../../../useTT.ts";
import {
  type CompanyDetailsFormShape,
  useCompanyDetailsForm,
} from "./useCompanyDetailsForm.ts";

type ContactPersonOption = {
  value: string;
  label: string;
  documentId: string;
  entityId: string;
};

type CompanyDetailsFormProps = {
  defaultValues: CompanyDetailsFormShape;
  onSubmit: (values: CompanyDetailsFormShape) => Promise<void>;
};

export function CompanyDetailsForm({
  defaultValues,
  onSubmit,
}: CompanyDetailsFormProps) {
  const { form, companyOptions, selectedCompany } = useCompanyDetailsForm({
    defaultValues,
    onSubmit,
  });
  const { tt } = useTT();

  const companyDocumentId = selectedCompany?.masterRoleRef?.documentId;

  const { data: contactPersonData } = useGetFlowpayCreditContactPersons(
    companyDocumentId,
    selectedCompany?.masterRoleRef?.entityId,
  );

  const contactPersonOptions = useMemo<ContactPersonOption[]>(() => {
    if (!contactPersonData?.documentList) return [];

    return contactPersonData.documentList
      .filter((person) => person.documentHeader.documentType === "LivePerson")
      .map((person) => {
        const doc = person as typeof person & {
          partyBasicInfo?: {
            entityHeader?: { entityId?: string };
          };
          roles?: {
            returnedItems?: Array<{
              entityData?: {
                personBasicInfo?: {
                  entityData?: { firstName?: string; surname?: string };
                };
                roleBasicInfo?: {
                  entityData?: {
                    masterRoleRef?: { documentId?: string };
                  };
                };
              };
            }>;
          };
        };

        const role = doc.roles?.returnedItems?.find(
