import { useQuery } from "@tanstack/react-query";
import { useMemo } from "react";

import {
  getCompanyFilterAttribute,
  useCompanyRequestorIdentity,
} from "@dfp/bw-react-api-party";
import { useSdkBwParty } from "@dfp/bw-sdk-bw-party/fe";

import { queryKeysMarketplace } from "../../../queryKeysMarketplace.ts";

export type ContactPersonOption = {
  value: string;
  label: string;
  documentId: string;
  entityId: string;
};

const contactPersonReadEntities = {
  partyBasicInfo: {},
  roles: {
    readEntities: {
      roleBasicInfo: {},
      personBasicInfo: {},
    },
  },
} as const;

export function useContactPersonList(
  companyDocumentId: string | undefined,
  companyEntityId: string | undefined,
) {
  const partyApi = useSdkBwParty();
  const { requestorIdentity } = useCompanyRequestorIdentity(
    companyDocumentId ?? "",
  );

  const filtering = useMemo(
    () =>
      getCompanyFilterAttribute(companyDocumentId ?? "", companyEntityId, [
        "ClientUser",
      ]),
    [companyDocumentId, companyEntityId],
  );

  const { data, isLoading } = useQuery({
    enabled: !!companyDocumentId && !!companyEntityId,
    queryKey: queryKeysMarketplace.bibbyFactoringContactPersons(
      companyDocumentId ?? "",
      companyEntityId ?? "",
    ),
    queryFn: async () => {
      return partyApi.getDocumentList(
        {
          readDocuments: {
            LivePerson: {
              readEntities: contactPersonReadEntities,
              filtering,
            },
          },
          paging: { pageSize: 100 },
        },
        { requestorIdentity },
      );
    },
  });

  const options = useMemo<ContactPersonOption[]>(() => {
    if (!data?.documentList) return [];

    return data.documentList
      .filter((person) => person.documentHeader.documentType === "LivePerson")
      .map((person) => {
        const doc = person as typeof person & {
          partyBasicInfo?: {
            entityHeader?: { entityId?: string };
          };
          roles?: {
            returnedItems?: Array<{
              entityData?: {
                personBasicInfo?: {
                  entityData?: { firstName?: string; surname?: string };
                };
                roleBasicInfo?: {
                  entityData?: {
                    roleType?: string;
                    masterRoleRef?: {
                      documentId?: string;
                      entityId?: string;
                    };
                  };
                };
              };
              entityHeader?: { entityId?: string };
            }>;
          };
        };

        const role = doc.roles?.returnedItems?.find(
          (r) =>
            r.entityData?.roleBasicInfo?.entityData?.masterRoleRef
              ?.documentId === companyDocumentId,
        );

        const firstName =
          role?.entityData?.personBasicInfo?.entityData?.firstName ?? "";
        const surname =
          role?.entityData?.personBasicInfo?.entityData?.surname ?? "";
        const fullName = [firstName, surname].filter(Boolean).join(" ");

        const entityId =
          doc.partyBasicInfo?.entityHeader?.entityId ??
          person.documentHeader.id;

        return {
          value: person.documentHeader.id,
          label: fullName || person.documentHeader.id,
          documentId: person.documentHeader.id,
          entityId,
        };
      });
  }, [data, companyDocumentId]);

  return { options, isLoading };
}

