import {
  ContractPageWrapper,
  StepperContentSkeleton,
} from "@dfp/bw-react-frame-contract-stepper-layout";

import {
  useCreateBusinessInsuranceEntity,
  useGetBusinessInsurance,
  useUpdateBusinessInsuranceEntity,
} from "../../query/index.ts";
