import { InventoryForm } from "./components/inventoryForm/index.ts";
import type { InventoryFormShape } from "./components/inventoryForm/index.ts";

export function BusinessInsuranceInventoryPage() {
  const { tt } = useTT();
  const { data: contract, isLoading, isError } = useGetBusinessInsurance();
  const { handleCoverageNavigation } = useCoverageNavigation("inventory");
  const { mutateAsync: updateEntity } = useUpdateBusinessInsuranceEntity({
    onSuccess: handleCoverageNavigation,
  });
  const { mutateAsync: createEntity } = useCreateBusinessInsuranceEntity({
    onSuccess: handleCoverageNavigation,
  });

  if (isLoading) {
    return <StepperContentSkeleton />;
  }

  if (isError || !contract) {
    return (
      <ContractPageWrapper>
        <Alert severity="error">
          {tt("insurance.sections.coverage.inventoryForm.error")}
        </Alert>
      </ContractPageWrapper>
    );
  }

  async function onSubmit(values: InventoryFormShape) {
    if (isNil(values.coverage) || !contract) return;

    const entityData = contract?.inventoryInsuranceCoverage?.entityData;

    const inventoryInsuranceCoverage = {
      entityData: { coverage: values.coverage },
    };

    if (!entityData) {
      await createEntity({
        contract,
        createEntity: {
          inventoryInsuranceCoverage,
        },
      });
    } else {
      await updateEntity({
        contract,
        updateEntity: {
          inventoryInsuranceCoverage,
        },
      });
    }
  }

  const defaultValues: InventoryFormShape = {
    coverage:
      contract?.inventoryInsuranceCoverage?.entityData?.coverage ?? null,
  };

  return (
    <ContractPageWrapper>
      <InventoryForm onSubmit={onSubmit} defaultValues={defaultValues} />
    </ContractPageWrapper>
  );
}

