import WarningAmberOutlinedIcon from "@mui/icons-material/WarningAmberOutlined";
import {
  ButtonBase,
  Collapse,
  Stack,
  Tooltip,
  Typography,
} from "@mui/material";
import { useState } from "react";

import { getFormShape, withForm } from "@dfp/react-form";

import type { TranslationKey } from "../../../../useTT.ts";
import { useTT } from "../../../../useTT.ts";
import { PayoutSelect } from "./PayoutSelect.tsx";
import { RiskControls } from "./RiskControls.tsx";
import { RiskRowHeader } from "./RiskRowHeader.tsx";
import type { RiskSectionProps } from "./RiskSectionDesktop.tsx";
import { RiskViewMoreLink } from "./RiskViewMoreLink.tsx";
import type { QuoteFormShape } from "./quoteForm.types.ts";

export const RiskSectionMobile = withForm({
  defaultValues: getFormShape<QuoteFormShape>(),
  props: {} as RiskSectionProps,
  render: function RiskSectionMobileInner({
    form,
    riskDef,
    enabled,
    packageId,
    sectionKey,
    riskNamespace,
    onToggle,
    isDescriptionOpen,
    metadata,
    showAnnualCost,
    titleWithIcon,
  }) {
    const { tt } = useTT();
    const [isExclusionOpen, setIsExclusionOpen] = useState(false);

    const descriptionKey =
      `insurance.sections.quote.risks.${riskNamespace}.${riskDef.id}.description` as TranslationKey;

    return (
      <Stack sx={{ gap: 1.5 }}>
        {/* Title Row */}
        <Stack
          sx={{
            flexDirection: "row",
            justifyContent: "space-between",
            alignItems: "flex-start",
            gap: 1,
          }}
        >
          {titleWithIcon}
          {!enabled && (
            <RiskControls
              isEnabled={false}
              metadata={metadata}
              annualCost={riskDef.annualCost}
              showAnnualCost={showAnnualCost}
              onToggle={onToggle}
            />
          )}
        </Stack>

        {/* Description */}
        <Collapse in={isDescriptionOpen}>
          {riskDef.exclusionTooltip ? (
            <Tooltip
              title={riskDef.exclusionTooltip}
              open={isExclusionOpen}
              onClose={() => setIsExclusionOpen(false)}
              disableHoverListener
              arrow
            >
              <ButtonBase
                onClick={() => setIsExclusionOpen((prev) => !prev)}
                sx={{ display: "block", textAlign: "left", width: "100%" }}
              >
                <Typography
                  id={`risk-description-mobile-${riskDef.id}`}
                  variant="body2"
                  component="span"
                  sx={{ color: "text.secondary" }}
                >
                  {tt(descriptionKey)}{" "}
                  <WarningAmberOutlinedIcon
                    sx={{
                      fontSize: 14,
                      color: "warning.main",
                      verticalAlign: "middle",
                    }}
                  />
                  <RiskViewMoreLink
                    riskDef={riskDef}
                    riskNamespace={riskNamespace}
                  />
                </Typography>
              </ButtonBase>
            </Tooltip>
          ) : (
            <Typography
              id={`risk-description-mobile-${riskDef.id}`}
              variant="body2"
              sx={{ color: "text.secondary" }}
            >
              {tt(descriptionKey)}
              <RiskViewMoreLink
                riskDef={riskDef}
                riskNamespace={riskNamespace}
              />
            </Typography>
          )}
        </Collapse>

        {/* Payout & Cost - only when enabled */}
        {enabled && (
          <>
            <RiskRowHeader showAnnualCost={showAnnualCost} />
            <Stack
              sx={{
                flexDirection: "row",
                gap: 2,
                alignItems: "flex-start",
              }}
            >
              <Stack
                sx={{
                  flex: 1,
                  alignItems: "flex-end",
                }}
              >
                <PayoutSelect
                  form={form}
                  payoutOptions={riskDef.payoutOptions}
                  metadata={metadata}
                  sectionKey={sectionKey}
                  riskId={riskDef.id}
                  packageId={packageId}
                />
              </Stack>
              <RiskControls
                isEnabled
                metadata={metadata}
                annualCost={riskDef.annualCost}
                showAnnualCost={showAnnualCost}
                onToggle={onToggle}
              />
            </Stack>
          </>
        )}
      </Stack>
    );
  },
});

