import { RiskViewMoreLink } from "./RiskViewMoreLink.tsx";
import type {
  QuoteFormShape,
  RiskDef,
  RiskMetadata,
} from "./quoteForm.types.ts";

export type RiskSectionProps = {
  riskDef: RiskDef;
  enabled: boolean;
  packageId: PackageTier;
  sectionKey: string;
  riskNamespace: string;
  onToggle: () => void;
  isDescriptionOpen: boolean;
  metadata: RiskMetadata;
  showAnnualCost: boolean;
  titleWithIcon: ReactNode;
};

export const RiskSectionDesktop = withForm({
  defaultValues: getFormShape<QuoteFormShape>(),
  props: {} as RiskSectionProps,
  render: function RiskSectionDesktopInner({
    form,
    riskDef,
    enabled,
    packageId,
    sectionKey,
    riskNamespace,
    onToggle,
    isDescriptionOpen,
    metadata,
    showAnnualCost,
    titleWithIcon,
  }) {
    const { tt } = useTT();
    const [isExclusionOpen, setIsExclusionOpen] = useState(false);

    const descriptionKey =
      `insurance.sections.quote.risks.${riskNamespace}.${riskDef.id}.description` as TranslationKey;

    return (
      <Box
        sx={{
          display: "grid",
          gridTemplateColumns: "1fr 1fr",
          gap: 2,
          alignItems: "flex-start",
        }}
      >
        {/* Risk Name & Description */}
        <Stack sx={{ gap: 0.5 }}>
          {titleWithIcon}
          <Collapse in={isDescriptionOpen}>
            {riskDef.exclusionTooltip ? (
              <Tooltip
                title={riskDef.exclusionTooltip}
                open={isExclusionOpen}
                onClose={() => setIsExclusionOpen(false)}
                disableHoverListener
                arrow
              >
                <ButtonBase
                  onClick={() => setIsExclusionOpen((prev) => !prev)}
                  sx={{ display: "block", textAlign: "left", width: "100%" }}
                >
                  <Typography
                    id={`risk-description-${riskDef.id}`}
                    variant="body2"
                    component="span"
                    sx={{ color: "text.secondary" }}
                  >
                    {tt(descriptionKey)}{" "}
                    <WarningAmberOutlinedIcon
                      sx={{
                        fontSize: 14,
                        color: "warning.main",
                        verticalAlign: "middle",
                      }}
                    />
                    <RiskViewMoreLink
                      riskDef={riskDef}
                      riskNamespace={riskNamespace}
                    />
                  </Typography>
                </ButtonBase>
              </Tooltip>
            ) : (
              <Typography
                id={`risk-description-${riskDef.id}`}
                variant="body2"
                sx={{ color: "text.secondary" }}
              >
                {tt(descriptionKey)}
                <RiskViewMoreLink
                  riskDef={riskDef}
                  riskNamespace={riskNamespace}
                />
              </Typography>
            )}
          </Collapse>
        </Stack>

        {/* Payout, Cost & Toggle */}
        <Box
          sx={{
            display: "grid",
            gridTemplateColumns: showAnnualCost ? "160px 70px 48px" : "1fr",
            gap: 2,
            alignItems: "flex-start",
          }}
        >
          {enabled ? (
            <PayoutSelect
              form={form}
              payoutOptions={riskDef.payoutOptions}
              metadata={metadata}
              packageId={packageId}
              sectionKey={sectionKey}
              riskId={riskDef.id}
            />
          ) : (
            <Box />
          )}

          <RiskControls
            isEnabled={enabled}
            metadata={metadata}
            annualCost={riskDef.annualCost}
            showAnnualCost={showAnnualCost}
            onToggle={onToggle}
          />
        </Box>
      </Box>
    );
  },
});

