import { Stack, Tooltip, Typography } from "@mui/material";
import { useEffect, useState } from "react";
import { createPortal } from "react-dom";

import { getFormShape } from "@dfp/react-form";
import { IconSave01, IconSend01 } from "@dfp/react-icons";

import { useTT } from "../useTT.ts";
import { COMMAND_LINE_ACTIONS_SLOT_ID } from "./consts.ts";
import {
  useInvoiceEditDialogContext,
  useInvoiceEntityData,
  useInvoiceValidation,
} from "./context/index.ts";
import { withInvoicesForm } from "./hooks/index.ts";
import type { InvoiceEditSubmitMeta } from "./types.ts";
import type { InvoiceEditFormShape } from "./utils/index.ts";

const CommandLineActionsInner = withInvoicesForm({
  defaultValues: getFormShape<InvoiceEditFormShape>(),
  render: function CommandLineActionsInnerRender({ form }) {
    const { tt } = useTT();
    const warnings = useInvoiceValidation();
    const hasFatalErrors = warnings.some((w) => w.fatal === true);
    const hasBannerIssues = warnings.length > 0;
    const dialogContext = useInvoiceEditDialogContext();
    const { onClose } = dialogContext ?? {};
    const entityData = useInvoiceEntityData();
    const isRejected =
      entityData?.invoiceBasicInfo?.entityData?.status === "Rejected";

    const sendForApprovalTooltip = hasBannerIssues ? (
      <>
        <Typography variant="body2" sx={{ fontWeight: 700 }}>
          {tt("commandLine.resolveInconsistencies")}
        </Typography>
        <Typography variant="body2">
          {tt("commandLine.approvalDisabledDescription")}
        </Typography>
      </>
    ) : (
      ""
    );

    return (
      <Stack sx={{ flexDirection: "row", gap: 1 }}>
        <form.Submit
          color="secondary"
          disabled={hasFatalErrors || isRejected}
          submitMeta={
            {
              type: "saveDraft",
              onSuccess: onClose,
            } satisfies InvoiceEditSubmitMeta
          }
          startIcon={<IconSave01 />}
        >
          {tt("invoiceDetail.saveAndClose")}
        </form.Submit>
        <Tooltip title={sendForApprovalTooltip} placement="top" arrow>
          <span>
            <form.Submit
              disabled={hasBannerIssues || isRejected}
              color="primary"
              startIcon={<IconSend01 />}
            >
              {tt("invoiceDetail.sendForApproval")}
            </form.Submit>
          </span>
        </Tooltip>
      </Stack>
    );
  },
});

export const CommandLineActions = withInvoicesForm({
  defaultValues: getFormShape<InvoiceEditFormShape>(),
  render: function CommandLineActionsRender({ form }) {
    const [portalContainer, setPortalContainer] = useState<HTMLElement | null>(
      null,
    );

    useEffect(() => {
      setPortalContainer(document.getElementById(COMMAND_LINE_ACTIONS_SLOT_ID));
    }, []);

    if (!portalContainer) {
      return <CommandLineActionsInner form={form} />;
    }

    return createPortal(
      <CommandLineActionsInner form={form} />,
      portalContainer,
    );
  },
});

