import {
  Box,
  Button,
  Collapse,
  Divider,
  IconButton,
  ListItemIcon,
  ListItemText,
  Menu,
  MenuItem,
  Stack,
  Typography,
} from "@mui/material";
import { Fragment, useState } from "react";

import { getFormShape } from "@dfp/react-form";
import {
  IconChevronDown,
  IconChevronUp,
  IconDotsVertical,
  IconPlus,
  IconTrash01,
} from "@dfp/react-icons";

import { useTT } from "../../../useTT.ts";
import {
  useSectionValidationWarnings,
  withInvoicesForm,
} from "../../hooks/index.ts";
import {
  type InvoiceEditFormShape,
  type InvoiceLine,
  SECTION_IDS,
  getInvoiceLineId,
} from "../../utils/index.ts";
import { GroupChip } from "../GroupChip.tsx";

const defaultInvoiceLine: InvoiceLine = {
  id: undefined,
  invoicedQuantity: undefined,
  lineExtensionAmount: undefined,
  lineExtensionTaxAmount: undefined,
  unitPrice: undefined,
  classifiedTaxCategory: {
    percent: undefined,
  },
  item: {
    description: undefined,
  },
};

let nextTempLineId = 0;
function generateTempLineEntityId(): string {
  return `_new_line_${nextTempLineId++}`;
}

export const InvoiceLines = withInvoicesForm({
  defaultValues: getFormShape<InvoiceEditFormShape>(),
  render: function InvoiceLinesInner({ form }) {
    const [isCollapsed, setIsCollapsed] = useState(false);
    const [menuAnchorEl, setMenuAnchorEl] = useState<null | HTMLElement>(null);
    const [menuIndex, setMenuIndex] = useState<number | null>(null);

    const handleMenuOpen = (
      event: React.MouseEvent<HTMLElement>,
      index: number,
    ) => {
      setMenuAnchorEl(event.currentTarget);
      setMenuIndex(index);
    };

    const handleMenuClose = () => {
      setMenuAnchorEl(null);
      setMenuIndex(null);
    };

    const toggleCollapse = () => {
      setIsCollapsed((prev) => !prev);
    };

    const { language, tt } = useTT();
    const allLineWarnings = useSectionValidationWarnings(["invoiceLines"]);

    return (
      <Stack id={SECTION_IDS.invoiceLines} sx={{ gap: 3 }}>
        <form.Field name="invoiceLines" mode="array">
          {(field) => {
            const lineCount = field.state.value?.length ?? 0;

            const handleDelete = () => {
              if (menuIndex === null) return;
              field.removeValue(menuIndex);
              handleMenuClose();
            };

            const handleAddLine = () => {
              field.pushValue({
                ...defaultInvoiceLine,
                _entityId: generateTempLineEntityId(),
              });
            };

            return (
              <>
                <Stack
                  sx={{
                    flexDirection: "row",
                    alignItems: "center",
                    justifyContent: "space-between",
                  }}
                >
                  <Stack
                    sx={{ flexDirection: "row", alignItems: "center", gap: 1 }}
                  >
                    <Typography
                      variant="h6"
                      sx={{ fontWeight: 700 }}
                      component="h2"
                    >
                      {tt("invoiceEditForm.sections.invoiceLines")}
                    </Typography>
                    <Box
                      sx={(theme) => ({
                        display: "grid",
                        placeItems: "center",
                        bgcolor: theme.palette.custom.surfaceTertiary,
                        color: theme.palette.text.secondary,
                        borderRadius: "6px",
                        minWidth: "24px",
                        height: "25px",
                      })}
                    >
                      <Typography variant="body3">{lineCount}</Typography>
                    </Box>
                    <GroupChip groupValidations={allLineWarnings} />
                  </Stack>
                  <Button
                    onClick={toggleCollapse}
                    color="secondary"
                    sx={{
                      display: "flex",
                      alignItems: "center",
                      gap: 0.5,
                      textDecoration: "none",
                      cursor: "pointer",
                    }}
                  >
                    {isCollapsed
                      ? tt("invoiceEditForm.actions.expandLines")
                      : tt("invoiceEditForm.actions.collapseLines")}
                    {isCollapsed ? (
                      <IconChevronDown width={16} height={16} />
                    ) : (
                      <IconChevronUp width={16} height={16} />
                    )}
                  </Button>
                </Stack>

                <Collapse in={!isCollapsed} unmountOnExit>
                  <Stack sx={{ gap: 2 }}>
                    {field.state.value?.map((item, index) => (
                      <Fragment key={item._entityId}>
                        <Box id={getInvoiceLineId(index)}>
                          <Stack
                            sx={{
                              flexDirection: "row",
                              justifyContent: "space-between",
                              alignItems: "center",
                              mb: 1,
                            }}
                          >
                            <Typography
                              variant="h4"
                              sx={{ fontWeight: 600, color: "text.secondary" }}
                              component="h4"
                            >
                              {tt("invoiceEditForm.lineItem", {
                                number: index + 1,
                              })}
                            </Typography>
                            <IconButton
                              size="small"
                              onClick={(e) => handleMenuOpen(e, index)}
                              aria-label={tt("invoiceEditForm.lineItemOptions")}
                            >
                              <IconDotsVertical width={20} height={20} />
                            </IconButton>
                          </Stack>
                          <Stack sx={{ gap: 2 }}>
                            <form.AppField
                              name={`invoiceLines[${index}].item.description`}
                            >
                              {(field) => (
                                <field.Text
                                  label={tt(
                                    "invoiceEditForm.invoiceLines.invoiceLine.item.description",
                                  )}
                                />
