import { useCallback } from "react";

import { useBankConnectionUrls } from "@dfp/bw-react-app-config";
import { useReconnectBankAccountQuery } from "@dfp/bw-react-dmb-bankaccounts";
import { useSnackbar } from "@dfp/react-components";

import type { BankAccountDocument } from "../types.ts";
import { useTT } from "../useTT.ts";

export function useReconnectBankAccount() {
  const { redirectUri } = useBankConnectionUrls();
  const { mutate: reconnectBankAccountMutation } =
    useReconnectBankAccountQuery();
  const { showSnackbar } = useSnackbar();
  const { tt } = useTT();

  const reconnectBankAccount = useCallback(
    (account: BankAccountDocument) => {
      const accountDocumentId = account.documentHeader?.id;
      const accountPaymentProvider =
        account.connectionInformation?.entityData?.paymentProvider;

      if (!accountDocumentId) {
        showSnackbar({
          message: tt("errors.reconnectFailed"),
          severity: "error",
        });
        return;
      }

      const callbackParams = new URLSearchParams({
        documentId: accountDocumentId,
        type: "expired",
        ...(accountPaymentProvider
          ? { paymentProvider: accountPaymentProvider }
          : {}),
      });

      reconnectBankAccountMutation(
        {
          documentId: accountDocumentId,
          callbackUrl: `${redirectUri}${window.location.pathname}?${callbackParams.toString()}`,
        },
        {
          onSuccess: (response) => {
            window.location.href = response.data.redirectUrl;
          },
          onError: () => {
            showSnackbar({
              message: tt("errors.reconnectFailed"),
              severity: "error",
            });
          },
        },
      );
    },
    [redirectUri, reconnectBankAccountMutation, showSnackbar, tt],
  );

  return { reconnectBankAccount };
}

import { useCallback } from "react";
import { useNavigate } from "react-router";

import { useBankConnectionUrls } from "@dfp/bw-react-app-config";
import { useReconnectBankAccountQuery } from "@dfp/bw-react-dmb-bankaccounts";
import { makeRoute, pathRoutes } from "@dfp/bw-react-routing";
import { useModals, useSnackbar } from "@dfp/react-components";

import type { AccountConnectedDocument } from "../types.ts";
import { useTT } from "../useTT.ts";
import { useNavigateToTransactions } from "./useNavigateToTransactions.ts";

export function useAccountActions() {
  const { redirectUri } = useBankConnectionUrls();
  const { navigateToTransactions } = useNavigateToTransactions();
  const navigate = useNavigate();
  const { showSnackbar } = useSnackbar();
  const { tt } = useTT();
  const { mutate: reconnectBankAccountMutation } =
    useReconnectBankAccountQuery();
  const { closeAll } = useModals();

  const handleViewDetailPage = useCallback(
    (account: AccountConnectedDocument) => {
      const companyId = account.partyRoleRef?.entityData.documentId;
      const accountId = account.documentHeader.id;

      if (companyId && accountId) {
        navigate(
          makeRoute(pathRoutes.accountDetail, {
            companyId,
            accountId,
          }),
        );
      }
    },
    [navigate],
  );

  const handleShowTransactions = useCallback(
    (doc: AccountConnectedDocument) => {
      const companyId = doc.partyRoleRef?.entityData.documentId;
      const accountId = doc.documentHeader.id;

      // Force-close the dialog stack synchronously so the backdrop doesn't get
      // stuck if navigation interrupts an in-progress close animation.
      closeAll({ force: true });
      navigateToTransactions({ accountId, companyId });
    },
    [closeAll, navigateToTransactions],
  );

  const handleReconnect = useCallback(
    (doc: AccountConnectedDocument) => {
      const accountDocumentId = doc.documentHeader?.id;
      const accountPaymentProvider =
        doc.connectionInformation?.entityData?.paymentProvider;

      if (!accountDocumentId) {
        showSnackbar({
          message: tt("errors.reconnectFailed"),
          severity: "error",
        });
        return;
      }

      const callbackParams = new URLSearchParams({
        documentId: accountDocumentId,
        type: "expired",
        ...(accountPaymentProvider
          ? { paymentProvider: accountPaymentProvider }
          : {}),
      });

      reconnectBankAccountMutation(
        {
          documentId: accountDocumentId,
          callbackUrl: `${redirectUri}${window.location.pathname}?${callbackParams.toString()}`,
        },
        {
          onSuccess: (response) => {
            window.location.href = response.data.redirectUrl;
          },
          onError: () => {
            showSnackbar({
              message: tt("errors.reconnectFailed"),
              severity: "error",
            });
          },
        },
      );
    },
    [redirectUri, reconnectBankAccountMutation, showSnackbar, tt],
  );

  return {
    handleViewDetailPage,
    handleShowTransactions,
    handleReconnect,
  };
}

