import type { AnyFormApi } from "@tanstack/form-core";

import { calculation } from "@dfp/bw-isomorphic-invoice";
import type { InvoiceDocument } from "@dfp/bw-isomorphic-invoice";

import type { SectionValidationWarning } from "../hooks/useSectionValidationWarnings.ts";
import type {
  InvoiceDataFormShape,
  InvoiceLine,
  TaxSubTotal,
} from "./types.ts";

export type InvoiceFormApi = AnyFormApi;

const nullToUndefined = (v: number | null | undefined): number | undefined =>
  v ?? undefined;

export type RecalculationAction = (
  form: InvoiceFormApi,
  warning: SectionValidationWarning,
) => void;

function toSdkLine(formLine: InvoiceLine) {
  return {
    invoicedQuantity: {
      value: nullToUndefined(formLine.invoicedQuantity),
    },
    unitPrice: { value: nullToUndefined(formLine.unitPrice) },
    classifiedTaxCategory: {
      percent: {
        value: nullToUndefined(formLine.classifiedTaxCategory?.percent),
      },
    },
    lineExtensionAmount: {
      value: nullToUndefined(formLine.lineExtensionAmount),
    },
    lineExtensionTaxAmount: {
      value: nullToUndefined(formLine.lineExtensionTaxAmount),
    },
    lineExtensionAmountTaxInclusive: {
      value: nullToUndefined(formLine.lineExtensionAmountTaxInclusive),
    },
  };
}

type SdkLine = ReturnType<typeof toSdkLine>;

function toSdkSubTotal(formSubTotal: TaxSubTotal) {
  return {
    taxCategory: {
      percent: {
        value: nullToUndefined(formSubTotal.taxCategory?.percent),
      },
    },
    taxableAmount: {
      value: nullToUndefined(formSubTotal.taxableAmount),
    },
    taxAmount: { value: nullToUndefined(formSubTotal.taxAmount) },
    taxInclusiveAmount: {
      value: nullToUndefined(formSubTotal.taxInclusiveAmount),
    },
  };
}

type SdkSubTotal = ReturnType<typeof toSdkSubTotal>;

/**
 * Converts form data and sdk subtotals to an SDK InvoiceData shape.
 */
function toSdkData(
  formData: InvoiceDataFormShape,
  sdkSubTotals: SdkSubTotal[],
) {
  return {
    taxTotal: {
      taxSubTotal: sdkSubTotals,
      taxAmount: {
        value: nullToUndefined(formData.taxTotal?.taxAmount),
      },
    },
    legalMonetaryTotal: {
      taxExclusiveAmount: {
        value: nullToUndefined(formData.legalMonetaryTotal?.taxExclusiveAmount),
      },
      taxInclusiveAmount: {
        value: nullToUndefined(formData.legalMonetaryTotal?.taxInclusiveAmount),
      },
      alreadyClaimedTaxExclusiveAmount: {
        value: nullToUndefined(
          formData.legalMonetaryTotal?.alreadyClaimedTaxExclusiveAmount,
        ),
      },
      alreadyClaimedTaxInclusiveAmount: {
        value: nullToUndefined(
          formData.legalMonetaryTotal?.alreadyClaimedTaxInclusiveAmount,
        ),
      },
      payableRoundingAmount: {
        value: nullToUndefined(
          formData.legalMonetaryTotal?.payableRoundingAmount,
        ),
      },
    },
  };
}

/**
 * Private helper: recomputes each taxSubTotal's taxableAmount, taxAmount, and
 * taxInclusiveAmount from line data. Used by AR2A, AR3A, AR3B, and AR11A.
 */
function recomputeSubTotalsFromLines(
  form: AnyFormApi,
  formSubTotals: TaxSubTotal[],
  sdkLines: SdkLine[],
): SdkSubTotal[] {
  const linesDocument: InvoiceDocument = { data: {}, lines: sdkLines };

  return formSubTotals.map((fs, i): SdkSubTotal => {
    const sdkSubTotal: SdkSubTotal = toSdkSubTotal(fs);

    const newTaxableAmount =
      calculation.footer.taxTotal.taxSubTotal.taxableAmount(
        sdkSubTotal,
        linesDocument,
      ) ?? 0;
    form.setFieldValue(
      `invoiceData.taxTotal.taxSubTotal[${i}].taxableAmount`,
      newTaxableAmount,
    );

    const newTaxAmount =
      calculation.footer.taxTotal.taxSubTotal.taxAmount(
        sdkSubTotal,
        linesDocument,
      ) ?? 0;
    form.setFieldValue(
      `invoiceData.taxTotal.taxSubTotal[${i}].taxAmount`,
      newTaxAmount,
    );

    sdkSubTotal.taxableAmount = { value: newTaxableAmount };
    sdkSubTotal.taxAmount = { value: newTaxAmount };

    const newTaxInclusiveAmount =
      calculation.footer.taxTotal.taxSubTotal.taxInclusiveAmount(
        sdkSubTotal,
        linesDocument,
      ) ?? 0;
    form.setFieldValue(
      `invoiceData.taxTotal.taxSubTotal[${i}].taxInclusiveAmount`,
      newTaxInclusiveAmount,
    );
    sdkSubTotal.taxInclusiveAmount = { value: newTaxInclusiveAmount };

    return sdkSubTotal;
  });
}

/**
 * Private helper: cascades updated subtotals into footer totals.
 * Called by AR2A, AR2B, AR3A, AR3B, and AR11A to avoid code duplication.
 * Computes and sets: taxExclusiveAmount, taxTotal.taxAmount, taxInclusiveAmount,
 * difference fields, and payableAmount.
 */
function cascadeFooterTotals(
  form: AnyFormApi,
  sdkSubTotals: SdkSubTotal[],
  formData: InvoiceDataFormShape,
  sdkLines: SdkLine[],
) {
  const sdkData = toSdkData(formData, sdkSubTotals);
  const document: InvoiceDocument = {
    data: sdkData,
    lines: sdkLines,
  };

  // AR3A — taxExclusiveAmount = sum of all taxSubTotal[].taxableAmount
  const newTaxExclusiveAmount =
    calculation.footer.legalMonetaryTotal.taxExclusiveAmount(document) ?? 0;
  form.setFieldValue(
    "invoiceData.legalMonetaryTotal.taxExclusiveAmount",
    newTaxExclusiveAmount,
  );

  // AR3D — taxTotal.taxAmount = sum of all taxSubTotal[].taxAmount
  const newTotalTaxAmount =
    calculation.footer.taxTotal.taxAmount(document) ?? 0;
  form.setFieldValue("invoiceData.taxTotal.taxAmount", newTotalTaxAmount);

  // AR3B — taxInclusiveAmount = sum of all taxSubTotal[].taxInclusiveAmount
  const newTaxInclusiveAmount =
    calculation.footer.legalMonetaryTotal.taxInclusiveAmount(document) ?? 0;
  form.setFieldValue(
    "invoiceData.legalMonetaryTotal.taxInclusiveAmount",
    newTaxInclusiveAmount,
  );

  // Recalculate difference fields.
  // Update SDK data with computed values so difference calculations see them.
  sdkData.legalMonetaryTotal.taxExclusiveAmount = {
    value: newTaxExclusiveAmount,
  };
  sdkData.legalMonetaryTotal.taxInclusiveAmount = {
    value: newTaxInclusiveAmount,
  };

  const newDifferenceTaxExclusiveAmount =
    calculation.footer.legalMonetaryTotal.differenceTaxExclusiveAmount(
      document,
    ) ?? 0;
  form.setFieldValue(
    "invoiceData.legalMonetaryTotal.differenceTaxExclusiveAmount",
    newDifferenceTaxExclusiveAmount,
  );

  // differenceTaxInclusiveAmount = taxInclusiveAmount - alreadyClaimedTaxInclusiveAmount
  const newDifferenceTaxInclusiveAmount =
    calculation.footer.legalMonetaryTotal.differenceTaxInclusiveAmount(
      document,
    ) ?? 0;
  form.setFieldValue(
    "invoiceData.legalMonetaryTotal.differenceTaxInclusiveAmount",
    newDifferenceTaxInclusiveAmount,
  );

  // AR3C — payableAmount = differenceTaxInclusiveAmount + payableRoundingAmount
  // CRITICAL: Uses differenceTaxInclusiveAmount, NOT raw taxInclusiveAmount.
  // No shared calculation matches this exact formula (payableAmount.usingTaxInclusiveAmount
  // uses taxInclusiveAmount - paidDepositsAmount + payableRoundingAmount, which differs).
  // todo: solve with BE devs
  const payableRoundingAmount =
    formData.legalMonetaryTotal?.payableRoundingAmount ?? 0;
  const newPayableAmount =
    newDifferenceTaxInclusiveAmount + payableRoundingAmount;
  form.setFieldValue(
    "invoiceData.legalMonetaryTotal.payableAmount",
    newPayableAmount,
  );
}

/**
 * VAL-AR1A: Recalculates line extension amount from unit price, then cascades
 * to lineExtensionTaxAmount and lineExtensionAmountTaxInclusive.
 * Formula: lineExtensionAmount = invoicedQuantity * unitPrice
 */
export function recalculateAR1A(
  form: AnyFormApi,
  warning: SectionValidationWarning,
) {
  const lineIndex = warning.lineIndex;
  if (lineIndex === undefined) return;
  const formLines = form.getFieldValue("invoiceLines");
  const formLine = formLines?.[lineIndex];
  if (!formLine) return;

  const sdkLine: SdkLine = toSdkLine(formLine);
  const document: InvoiceDocument = { data: {}, lines: [] };

  const lineExtensionAmount =
    calculation.line.lineExtensionAmount.usingUnitPrice(sdkLine, document) ?? 0;
  form.setFieldValue(
    `invoiceLines[${lineIndex}].lineExtensionAmount`,
    lineExtensionAmount,
  );

  // Update SDK line so subsequent calculations see the new value
  sdkLine.lineExtensionAmount = { value: lineExtensionAmount };

  // CASCADE: lineExtensionTaxAmount = lineExtensionAmount * percent / 100
  const lineExtensionTaxAmount =
    calculation.line.lineExtensionTaxAmount(sdkLine, document) ?? 0;
  form.setFieldValue(
    `invoiceLines[${lineIndex}].lineExtensionTaxAmount`,
    lineExtensionTaxAmount,
  );

  // Update SDK line so subsequent calculations see the new value
  sdkLine.lineExtensionTaxAmount = { value: lineExtensionTaxAmount };

  // CASCADE: lineExtensionAmountTaxInclusive = lineExtensionAmount + lineExtensionTaxAmount
  const lineExtensionAmountTaxInclusive =
    calculation.line.lineExtensionAmountTaxInclusive(sdkLine, document) ?? 0;
  form.setFieldValue(
    `invoiceLines[${lineIndex}].lineExtensionAmountTaxInclusive`,
    lineExtensionAmountTaxInclusive,
  );
}

/**
 * VAL-AR1B: Recalculates line tax amount from base amount and percent, then cascades
 * to lineExtensionAmountTaxInclusive. Does NOT recompute lineExtensionAmount.
 */
export function recalculateAR1B(
  form: AnyFormApi,
  warning: SectionValidationWarning,
) {
  const lineIndex = warning.lineIndex;
  if (lineIndex === undefined) return;
  const formLines = form.getFieldValue("invoiceLines");
  const formLine = formLines?.[lineIndex];
  if (!formLine) return;

  const sdkLine: SdkLine = toSdkLine(formLine);
  const document: InvoiceDocument = { data: {}, lines: [] };

  // NOTE: Do NOT recompute lineExtensionAmount — that's AR1A's job.
  const lineExtensionTaxAmount =
    calculation.line.lineExtensionTaxAmount(sdkLine, document) ?? 0;
  form.setFieldValue(
    `invoiceLines[${lineIndex}].lineExtensionTaxAmount`,
    lineExtensionTaxAmount,
  );

  // Update SDK line so subsequent calculation sees the new tax amount
  sdkLine.lineExtensionTaxAmount = { value: lineExtensionTaxAmount };

  // CASCADE: lineExtensionAmountTaxInclusive = lineExtensionAmount + lineExtensionTaxAmount
  const lineExtensionAmountTaxInclusive =
    calculation.line.lineExtensionAmountTaxInclusive(sdkLine, document) ?? 0;
  form.setFieldValue(
    `invoiceLines[${lineIndex}].lineExtensionAmountTaxInclusive`,
    lineExtensionAmountTaxInclusive,
  );
}

/**
 * VAL-AR2A: Recalculates each taxSubTotal's taxableAmount AND taxAmount from lines,
 * then cascades to all footer totals.
 */
export function recalculateAR2A(
  form: AnyFormApi,
  _warning: SectionValidationWarning,
) {
  const formValues = form.state.values;
  if (!formValues) return;

  const formLines = formValues.invoiceLines ?? [];
  const formData = formValues.invoiceData;
  const formSubTotals: TaxSubTotal[] = formData.taxTotal?.taxSubTotal ?? [];

  const sdkLines = formLines.map(toSdkLine);

  // Step 1: Recalculate each taxSubTotal entry — taxableAmount and taxAmount from lines
  const sdkSubTotals = recomputeSubTotalsFromLines(
    form,
    formSubTotals,
    sdkLines,
  );

  // Step 2: CASCADE to all footer totals
  cascadeFooterTotals(form, sdkSubTotals, formData, sdkLines);
}

/**
 * VAL-AR2B: Recalculates each taxSubTotal's taxAmount from taxableAmount * percent,
 * then cascades to all footer totals.
 */
export function recalculateAR2B(
  form: AnyFormApi,
  _warning: SectionValidationWarning,
) {
  const formValues = form.state.values;
  if (!formValues) return;

  const formLines = formValues.invoiceLines ?? [];
  const formData = formValues.invoiceData;
  const formSubTotals: TaxSubTotal[] = formData.taxTotal?.taxSubTotal ?? [];

  const sdkLines = formLines.map(toSdkLine);

  // Step 1: Recompute each taxSubTotal's taxAmount from taxableAmount * percent / 100
  const sdkSubTotals = formSubTotals.map((fs, i): SdkSubTotal => {
    const sdkSubTotal: SdkSubTotal = toSdkSubTotal(fs);

    // AR2B formula: taxAmount = taxableAmount * percent / 100
    // No calculation.* function covers this exact computation (the SDK's taxAmount sums lines).
    const taxableAmount = fs.taxableAmount ?? 0;
    const percent = fs.taxCategory?.percent ?? 0;
    const newTaxAmount = taxableAmount * (percent / 100);
    form.setFieldValue(
      `invoiceData.taxTotal.taxSubTotal[${i}].taxAmount`,
      newTaxAmount,
    );

    // Update SDK subtotal with new taxAmount so downstream calculations see it
    sdkSubTotal.taxAmount = { value: newTaxAmount };

    // Compute taxInclusiveAmount = taxableAmount + taxAmount
    const newTaxInclusiveAmount = taxableAmount + newTaxAmount;
    form.setFieldValue(
      `invoiceData.taxTotal.taxSubTotal[${i}].taxInclusiveAmount`,
      newTaxInclusiveAmount,
    );
    sdkSubTotal.taxInclusiveAmount = { value: newTaxInclusiveAmount };

    return sdkSubTotal;
  });

  // Step 2: CASCADE to all footer totals
  cascadeFooterTotals(form, sdkSubTotals, formData, sdkLines);
}

/**
 * VAL-AR3A: Recalculates taxExclusiveAmount from line amounts, then cascades to
 * difference fields and payableAmount.
 *
 * Previously this handler used stale subtotal values directly from the form, which
 * could produce 0 or wrong results when OCR data had incorrect subtotal taxableAmounts.
 * The VAL-AR3A validation checks taxExclusiveAmount against sum-of-LINE-amounts, so
 * the fix must also derive values from lines — consistent with what the validation expects.
 *
 * Fix: first recompute each subtotal's taxableAmount, taxAmount, and taxInclusiveAmount
 * from lines (same as AR2A / AR11A), then pass the updated subtotals to cascadeFooterTotals.
 */
export function recalculateAR3A(
  form: AnyFormApi,
  _warning: SectionValidationWarning,
) {
  const formValues = form.state.values;
  if (!formValues) return;

  const formLines = formValues.invoiceLines ?? [];
  const formData = formValues.invoiceData;
  const formSubTotals: TaxSubTotal[] = formData.taxTotal?.taxSubTotal ?? [];

  const sdkLines = formLines.map(toSdkLine);

  // Step 1: Recompute each taxSubTotal from lines.
  // This ensures subtotals are consistent with line amounts before cascading,
  // which prevents footer totals from being computed from stale/zero subtotal values.
  const sdkSubTotals = recomputeSubTotalsFromLines(
    form,
    formSubTotals,
    sdkLines,
  );

  // Step 2: CASCADE to all footer totals with correctly computed subtotals
  cascadeFooterTotals(form, sdkSubTotals, formData, sdkLines);
}

/**
 * VAL-AR3B: Recalculates taxInclusiveAmount from line amounts, then cascades to
 * difference fields and payableAmount.
 *
 * Previously this handler used stale subtotal values directly from the form, which
 * could produce wrong results when OCR data had incorrect subtotal values.
 * The same fix as AR3A: recompute subtotals from lines before cascading.
 */
export function recalculateAR3B(
  form: AnyFormApi,
  _warning: SectionValidationWarning,
) {
  const formValues = form.state.values;
  if (!formValues) return;

  const formLines = formValues.invoiceLines ?? [];
  const formData = formValues.invoiceData;
  const formSubTotals: TaxSubTotal[] = formData.taxTotal?.taxSubTotal ?? [];

  const sdkLines = formLines.map(toSdkLine);

  // Step 1: Recompute each taxSubTotal from lines.
  const sdkSubTotals = recomputeSubTotalsFromLines(
    form,
    formSubTotals,
    sdkLines,
  );

  // Step 2: CASCADE to all footer totals with correctly computed subtotals
  cascadeFooterTotals(form, sdkSubTotals, formData, sdkLines);
}

/**
 * VAL-AR3C: Recalculates payableAmount from differenceTaxInclusiveAmount + payableRoundingAmount.
 */
export function recalculateAR3C(
  form: AnyFormApi,
  _warning: SectionValidationWarning,
) {
  const formValues = form.state.values;
  if (!formValues) return;

  const formData = formValues.invoiceData;

  const differenceTaxInclusiveAmount =
    formData.legalMonetaryTotal?.differenceTaxInclusiveAmount ?? 0;
  const payableRoundingAmount =
    formData.legalMonetaryTotal?.payableRoundingAmount ?? 0;

  const newPayableAmount = differenceTaxInclusiveAmount + payableRoundingAmount;
  form.setFieldValue(
    "invoiceData.legalMonetaryTotal.payableAmount",
    newPayableAmount,
  );
}

/**
 * VAL-AR3D: Recalculates taxTotal.taxAmount from the sum of all taxSubTotal amounts.
 */
export function recalculateAR3D(
  form: AnyFormApi,
  _warning: SectionValidationWarning,
) {
  const formValues = form.state.values;
  if (!formValues) return;

  const formLines = formValues.invoiceLines ?? [];
  const formData = formValues.invoiceData;
  const formSubTotals: TaxSubTotal[] = formData.taxTotal?.taxSubTotal ?? [];

  const sdkLines = formLines.map(toSdkLine);
  // Use current form values for subtotals — do not recompute them (AR2x's job)
  const sdkSubTotals = formSubTotals.map(toSdkSubTotal);

  const sdkData = toSdkData(formData, sdkSubTotals);
  const document: InvoiceDocument = {
    data: sdkData,
    lines: sdkLines,
  };

  const newTotalTaxAmount =
    calculation.footer.taxTotal.taxAmount(document) ?? 0;
  form.setFieldValue("invoiceData.taxTotal.taxAmount", newTotalTaxAmount);
}

/**
 * VAL-AR11A: Full footer recalculation from lines — recalculates all subtotals from
 * line data, then cascades to all footer totals. This is the "recalculate everything"
 * handler equivalent to AR2A + all AR3x combined.
 */
export function recalculateAR11A(
  form: AnyFormApi,
  _warning: SectionValidationWarning,
) {
  const formValues = form.state.values;
  if (!formValues) return;

  const formLines = formValues.invoiceLines ?? [];
  const formData = formValues.invoiceData;
  const formSubTotals: TaxSubTotal[] = formData.taxTotal?.taxSubTotal ?? [];

  const sdkLines = formLines.map(toSdkLine);

  // Step 1: Recalculate each taxSubTotal entry from lines
  const sdkSubTotals = recomputeSubTotalsFromLines(
    form,
    formSubTotals,
    sdkLines,
  );

  // Step 2: CASCADE to all footer totals
  cascadeFooterTotals(form, sdkSubTotals, formData, sdkLines);
}

import { isNil } from "ramda";

import type { UpdateInvoiceParams } from "../../query/index.ts";
import type { UpdateEntityPayloadReqCreateInvoice } from "../../utils/index.ts";
import type { InvoiceDataFormShape, InvoiceEditFormShape } from "./types.ts";

/**
 * Type for the invoiceAllData.entityData path in the update payload.
 * This is the correct structure matching InvoiceAllDataUpdate from the SDK.
 */
type InvoiceAllDataEntityDataUpdate = NonNullable<
  NonNullable<
    UpdateEntityPayloadReqCreateInvoice["invoiceAllData"]
  >["entityData"]
>;

/**
 * Type for a single invoice line item in the flat array.
 */
type InvoiceLineItem = NonNullable<
  InvoiceAllDataEntityDataUpdate["invoiceLines"]
>[number];

/**
 * Helper to wrap a value in the { value } structure expected by the API.
 * Returns undefined if the value is undefined/null to avoid sending empty fields.
 */
function wrapValue<T>(value: T | undefined | null) {
  if (isNil(value)) {
    return undefined;
  }
  return { value };
}

/**
 * Maps invoice lines from form values to the flat array structure.
 * Uses full replacement strategy - all lines are sent on every update.
 * Existing lines (with _entityId) include entityHeader for updates.
 * New lines (without _entityId) are created.
 */
function mapLinesToUpdatePayload(
  lines: NonNullable<InvoiceEditFormShape>["invoiceLines"] | undefined,
): NonNullable<InvoiceAllDataEntityDataUpdate["invoiceLines"]> | undefined {
  if (!lines?.length) {
    return undefined;
  }

  return lines.map((line): InvoiceLineItem => {
    return {
      ...(line._entityId && {
        entityHeader: { entityId: line._entityId },
      }),
      entityData: {
        ...(wrapValue(line.id) && { id: wrapValue(line.id) }),
        ...(wrapValue(line.invoicedQuantity) && {
          invoicedQuantity: wrapValue(line.invoicedQuantity),
        }),
        ...(wrapValue(line.lineExtensionAmount) && {
          lineExtensionAmount: wrapValue(line.lineExtensionAmount),
        }),
        ...(wrapValue(line.lineExtensionAmountTaxInclusive) && {
          lineExtensionAmountTaxInclusive: wrapValue(
            line.lineExtensionAmountTaxInclusive,
          ),
        }),
        ...(wrapValue(line.lineExtensionTaxAmount) && {
          lineExtensionTaxAmount: wrapValue(line.lineExtensionTaxAmount),
        }),
        ...(wrapValue(line.unitPrice) && {
          unitPrice: wrapValue(line.unitPrice),
        }),
        ...(wrapValue(line.classifiedTaxCategory?.percent) && {
          classifiedTaxCategory: {
            percent: wrapValue(line.classifiedTaxCategory?.percent),
          },
        }),
        ...(wrapValue(line.item?.description) && {
          item: {
            description: wrapValue(line.item?.description),
          },
        }),
      },
    };
  });
}

/**
 * Maps invoiceData form values to the update payload structure.
 * Extracted helper for the invoiceData portion of the full form.
 */
function mapInvoiceDataToUpdatePayload(
  formValues: InvoiceDataFormShape | undefined,
): NonNullable<InvoiceAllDataEntityDataUpdate["invoiceData"]> {
  if (isNil(formValues)) {
    return {};
  }

  return {
    entityData: {
      ...(wrapValue(formValues.id) && { id: wrapValue(formValues.id) }),
      ...(wrapValue(formValues.issueDate) && {
        issueDate: wrapValue(formValues.issueDate),
      }),
      ...(wrapValue(formValues.documentType) && {
        documentType: wrapValue(formValues.documentType),
      }),
      ...(wrapValue(formValues.uuid) && { uuid: wrapValue(formValues.uuid) }),
      ...(wrapValue(formValues.issuingSystem) && {
        issuingSystem: wrapValue(formValues.issuingSystem),
      }),
      ...(wrapValue(formValues.taxPointDate) && {
        taxPointDate: wrapValue(formValues.taxPointDate),
      }),
      ...(formValues.vatApplicable != null &&
        formValues.vatApplicable !== "" && {
          vatApplicable: wrapValue(formValues.vatApplicable === "true"),
        }),
      ...(wrapValue(formValues.note) && {
        note: wrapValue(formValues.note),
      }),
      ...(wrapValue(formValues.localCurrencyCode) && {
        localCurrencyCode: wrapValue(formValues.localCurrencyCode),
      }),
      ...(wrapValue(formValues.currRate) && {
        currRate: wrapValue(formValues.currRate),
      }),

      // Supplier party - flat nested objects without entityData wrappers
      ...(formValues.accountingSupplierParty?.party && {
        accountingSupplierParty: {
          party: (() => {
            const postalAddress =
              formValues.accountingSupplierParty.party.postalAddress;
            const postalAddressData = {
              ...(wrapValue(postalAddress?.streetName) && {
                streetName: wrapValue(postalAddress?.streetName),
              }),
              ...(wrapValue(postalAddress?.buildingNumber) && {
                buildingNumber: wrapValue(postalAddress?.buildingNumber),
              }),
              ...(wrapValue(postalAddress?.cityName) && {
                cityName: wrapValue(postalAddress?.cityName),
              }),
              ...(wrapValue(postalAddress?.postalZone) && {
                postalZone: wrapValue(postalAddress?.postalZone),
              }),
              ...(wrapValue(postalAddress?.country?.name) && {
                country: {
                  name: wrapValue(postalAddress?.country?.name),
                },
              }),
            };
            const hasPostalAddress = Object.keys(postalAddressData).length > 0;

            return {
              ...(wrapValue(
                formValues.accountingSupplierParty.party.partyIdentification
                  ?.id,
              ) && {
                partyIdentification: {
                  id: wrapValue(
                    formValues.accountingSupplierParty.party.partyIdentification
                      ?.id,
                  ),
                },
              }),
              ...(wrapValue(
                formValues.accountingSupplierParty.party.partyName?.name,
              ) && {
                partyName: {
                  name: wrapValue(
                    formValues.accountingSupplierParty.party.partyName?.name,
                  ),
                },
              }),
              ...(wrapValue(
                formValues.accountingSupplierParty.party.partyTaxScheme
                  ?.companyID,
              ) && {
                partyTaxScheme: {
                  companyID: wrapValue(
                    formValues.accountingSupplierParty.party.partyTaxScheme
                      ?.companyID,
                  ),
                },
              }),
              ...(hasPostalAddress && {
                postalAddress: postalAddressData,
              }),
            };
          })(),
        },
      }),

      // Tax total - flat nested structure
      ...(formValues.taxTotal && {
        taxTotal: {
          ...(wrapValue(formValues.taxTotal.taxAmount) && {
            taxAmount: wrapValue(formValues.taxTotal.taxAmount),
          }),
          ...(formValues.taxTotal.taxSubTotal?.length && {
            taxSubTotal: formValues.taxTotal.taxSubTotal.map((item) => ({
              ...(wrapValue(item.taxableAmount) && {
                taxableAmount: wrapValue(item.taxableAmount),
              }),
              ...(wrapValue(item.taxAmount) && {
                taxAmount: wrapValue(item.taxAmount),
              }),
              ...(wrapValue(item.alreadyClaimedTaxableAmount) && {
                alreadyClaimedTaxableAmount: wrapValue(
                  item.alreadyClaimedTaxableAmount,
                ),
              }),
              ...(wrapValue(item.alreadyClaimedTaxAmount) && {
                alreadyClaimedTaxAmount: wrapValue(
                  item.alreadyClaimedTaxAmount,
                ),
              }),
              ...(wrapValue(item.alreadyClaimedTaxInclusiveAmount) && {
                alreadyClaimedTaxInclusiveAmount: wrapValue(
                  item.alreadyClaimedTaxInclusiveAmount,
                ),
              }),
              ...(wrapValue(item.differenceTaxableAmount) && {
                differenceTaxableAmount: wrapValue(
                  item.differenceTaxableAmount,
                ),
              }),
              ...(wrapValue(item.differenceTaxAmount) && {
                differenceTaxAmount: wrapValue(item.differenceTaxAmount),
              }),
              ...(wrapValue(item.differenceTaxInclusiveAmount) && {
                differenceTaxInclusiveAmount: wrapValue(
                  item.differenceTaxInclusiveAmount,
                ),
              }),
              ...(wrapValue(item.taxCategory?.percent) && {
                taxCategory: {
                  percent: wrapValue(item.taxCategory?.percent),
                },
              }),
            })),
          }),
        },
      }),

      // Legal monetary total - flat structure
      ...(() => {
        if (!formValues.legalMonetaryTotal) return {};

        const legalMonetaryTotalData = {
          ...(wrapValue(formValues.legalMonetaryTotal.taxExclusiveAmount) && {
            taxExclusiveAmount: wrapValue(
              formValues.legalMonetaryTotal.taxExclusiveAmount,
            ),
          }),
          ...(wrapValue(formValues.legalMonetaryTotal.taxInclusiveAmount) && {
            taxInclusiveAmount: wrapValue(
              formValues.legalMonetaryTotal.taxInclusiveAmount,
            ),
          }),
          ...(wrapValue(
            formValues.legalMonetaryTotal.alreadyClaimedTaxExclusiveAmount,
          ) && {
            alreadyClaimedTaxExclusiveAmount: wrapValue(
              formValues.legalMonetaryTotal.alreadyClaimedTaxExclusiveAmount,
            ),
          }),
          ...(wrapValue(
            formValues.legalMonetaryTotal.alreadyClaimedTaxInclusiveAmount,
          ) && {
            alreadyClaimedTaxInclusiveAmount: wrapValue(
              formValues.legalMonetaryTotal.alreadyClaimedTaxInclusiveAmount,
            ),
          }),
          ...(wrapValue(
            formValues.legalMonetaryTotal.differenceTaxExclusiveAmount,
          ) && {
            differenceTaxExclusiveAmount: wrapValue(
              formValues.legalMonetaryTotal.differenceTaxExclusiveAmount,
            ),
          }),
          ...(wrapValue(
            formValues.legalMonetaryTotal.differenceTaxInclusiveAmount,
          ) && {
            differenceTaxInclusiveAmount: wrapValue(
              formValues.legalMonetaryTotal.differenceTaxInclusiveAmount,
            ),
          }),
          ...(wrapValue(formValues.legalMonetaryTotal.payableAmount) && {
            payableAmount: wrapValue(
              formValues.legalMonetaryTotal.payableAmount,
            ),
          }),
        };

        if (Object.keys(legalMonetaryTotalData).length === 0) return {};

        return {
          legalMonetaryTotal: legalMonetaryTotalData,
        };
      })(),

      // Payment means - flat array structure
      ...(formValues.paymentMeans?.payment?.length && {
        paymentMeans: {
          payment: formValues.paymentMeans.payment.map((item) => {
            const detailsData = {
              ...(wrapValue(item.details?.id) && {
                id: wrapValue(item.details?.id),
              }),
              ...(wrapValue(item.details?.paymentDueDate) && {
                paymentDueDate: wrapValue(item.details?.paymentDueDate),
              }),
              ...(wrapValue(item.details?.bankCode) && {
                bankCode: wrapValue(item.details?.bankCode),
              }),
              ...(wrapValue(item.details?.name) && {
                name: wrapValue(item.details?.name),
              }),
              ...(wrapValue(item.details?.constantSymbol) && {
                constantSymbol: wrapValue(item.details?.constantSymbol),
              }),
              ...(wrapValue(item.details?.specificSymbol) && {
                specificSymbol: wrapValue(item.details?.specificSymbol),
              }),
              ...(wrapValue(item.details?.iban) && {
                iban: wrapValue(item.details?.iban),
              }),
              ...(wrapValue(item.details?.bic) && {
                bic: wrapValue(item.details?.bic),
              }),
              ...(wrapValue(item.details?.variableSymbol) && {
                variableSymbol: wrapValue(item.details?.variableSymbol),
              }),
            };

            const hasDetails = Object.keys(detailsData).length > 0;

            return {
              ...(wrapValue(item.paymentMeansCode) && {
                paymentMeansCode: wrapValue(item.paymentMeansCode),
              }),
              ...(wrapValue(item.paidAmount) && {
                paidAmount: wrapValue(item.paidAmount),
              }),
              ...(hasDetails && {
                details: detailsData,
              }),
            };
          }),
        },
      }),
    },
  };
}

/**
 * Maps flat form values to the invoiceAllData.entityData structure expected by the API.
 * This is the inverse of getDefaultValuesFromInvoiceData.
 * Produces the full invoiceAllData wrapper with both invoiceData and invoiceLines using the entityData path.
 */
export function mapFormValuesToUpdateEntityData(
  formValues: NonNullable<InvoiceEditFormShape>,
) {
  const mappedInvoiceData = mapInvoiceDataToUpdatePayload(
    formValues.invoiceData,
  );
  const mappedLines = mapLinesToUpdatePayload(formValues.invoiceLines);

  return {
    invoiceAllData: {
      entityData: {
        invoiceBasicInfo: {
          entityData: {
            // todo: replace with the right status in the future - right now, it should only be draft
            status: "Draft" as const,
            showMissingFields: undefined as boolean | undefined,
          },
        },
        invoiceData: mappedInvoiceData,
        ...(mappedLines && { invoiceLines: mappedLines }),
      },
    },
  } satisfies UpdateInvoiceParams["updateEntityData"];
}

import type {
  PackageResult,
  PackageSectionRisk,
  PackagesByTier,
} from "../../../../query/index.ts";
import type { PackageTier } from "../../../../query/quoteApiTypes.ts";
import type { BusinessInsuranceContract } from "./buildInitCalculationRequest.ts";
import type {
  QuoteFormShape,
  RiskValues,
  SectionValues,
} from "./quoteForm.types.ts";
import { deductibleValueMap } from "./quoteForm.utils.ts";

type ContractPolicyEntityData = NonNullable<
  NonNullable<
    BusinessInsuranceContract["businessInsurancePolicyEssential"]
  >["entityData"]
>;

export function toPackagesByTier(
  packages: PackageResult[],
): PackagesByTier | null {
  const essential = packages.find((pkg) => pkg.id === "1");
  const smart = packages.find((pkg) => pkg.id === "2");
  const premium = packages.find((pkg) => pkg.id === "3");
  if (!essential || !smart || !premium) return null;
  return { essential, smart, premium };
}

// Extracts enabled state and fixed payout value from a risk section.
function riskValues(risk?: PackageSectionRisk): RiskValues {
  return { enabled: risk?.selected === "1", payoutValue: risk?.value ?? "" };
}

// Like riskValues, but derives the payout from a percentage of baseValue when no fixed value is set.
function pctRiskValues(
  risk?: PackageSectionRisk,
  baseValue?: string,
): RiskValues {
  let payoutValue = risk?.value ?? "";
  if (!payoutValue && risk?.pctValue && baseValue) {
    payoutValue = String(
      Math.round(parseFloat(baseValue) * parseFloat(risk.pctValue)),
    );
  }
  return { enabled: risk?.selected === "1", payoutValue };
}

// Transforms a raw package result into the form's section/risk shape for a single tier.
function buildSections(pkg: PackageResult): Record<string, SectionValues> {
  const sections: Record<string, SectionValues> = {};

  // Buildings — one entry per address (insObject index)
  // EP always returns 10 insObject items — unused slots have riskFlexa.value="-1", skip those.
  // riskFlexa has no user toggle (showToggle: false) — value and selected come from the insObject.
  const validBuildingInsObjects = (pkg.buildings?.insObject ?? []).filter(
    (insObj) => insObj.riskFlexa?.value !== "-1",
  );
  for (let index = 0; index < validBuildingInsObjects.length; index++) {
    const buildingInsObject = validBuildingInsObjects[index];
    const baseValue = buildingInsObject?.riskFlexa?.value;
    sections[`buildings_${index}`] = {
      risks: {
        riskFlexa: {
          enabled: buildingInsObject?.riskFlexa?.selected === "1",
          payoutValue: buildingInsObject?.riskFlexa?.value ?? "",
        },
        riskNatural: pctRiskValues(pkg.buildings?.riskNatural, baseValue),
        riskFlood: pctRiskValues(pkg.buildings?.riskFlood, baseValue),
        riskTheft: riskValues(pkg.buildings?.riskTheft),
        riskVandal: riskValues(pkg.buildings?.riskVandal),
        riskGlass: riskValues(pkg.buildings?.riskGlass),
        deductible: riskValues(pkg.buildings?.deductible),
      },
    };
  }

  // Stocks
  if (pkg.stocks) {
    const stocksInsObject = pkg.stocks.insObject?.[0];
    const stocksBaseValue = stocksInsObject?.riskFlexa?.value;
    sections.stocks = {
      risks: {
        riskFlexa: {
          enabled: stocksInsObject?.riskFlexa?.selected === "1",
          payoutValue: stocksInsObject?.riskFlexa?.value ?? "",
        },
        riskNatural: pctRiskValues(pkg.stocks.riskNatural, stocksBaseValue),
        riskTheft: riskValues(pkg.stocks.riskTheft),
        riskFlood: pctRiskValues(pkg.stocks.riskFlood, stocksBaseValue),
        riskVandal: riskValues(pkg.stocks.riskVandal),
        riskTheftMoney: riskValues(pkg.stocks.riskTheftMoney),
        deductible: riskValues(pkg.stocks.deductible),
      },
    };
  }

  // Enginery
  if (pkg.enginery) {
    const engineryInsObject = pkg.enginery.insObject?.[0];
    const engineryBaseValue = engineryInsObject?.riskFlexa?.value;
    sections.enginery = {
      risks: {
        riskFlexa: {
          enabled: engineryInsObject?.riskFlexa?.selected === "1",
          payoutValue: engineryInsObject?.riskFlexa?.value ?? "",
        },
        riskNatural: pctRiskValues(pkg.enginery.riskNatural, engineryBaseValue),
        riskTheft: riskValues(pkg.enginery.riskTheft),
        riskFlood: pctRiskValues(pkg.enginery.riskFlood, engineryBaseValue),
        riskVandal: riskValues(pkg.enginery.riskVandal),
        riskSpecial: pctRiskValues(pkg.enginery.riskSpecial, engineryBaseValue),
        deductible: riskValues(pkg.enginery.deductible),
        deductibleSpecial: riskValues(pkg.enginery.deductibleSpecial),
      },
    };
  }

  // Liability
  if (pkg.liability) {
    const liabilityBaseValue = pkg.liability.riskBasic?.value;
    sections.liability = {
      risks: {
        riskBasic: riskValues(pkg.liability.riskBasic),
        riskHealthy: riskValues(pkg.liability.riskHealthy),
        riskFinancialHarm: riskValues(pkg.liability.riskFinancialHarm),
        riskNonpecuniaryHarm: riskValues(pkg.liability.riskNonpecuniaryHarm),
        riskRegresInsurance: pctRiskValues(
          pkg.liability.riskRegresInsurance,
          liabilityBaseValue,
        ),
        riskDefectThings: riskValues(pkg.liability.riskDefectThings),
        riskDeferred: pctRiskValues(
          pkg.liability.riskDeferred,
          liabilityBaseValue,
        ),
        riskUsedThings: riskValues(pkg.liability.riskUsedThings),
        validityArea: riskValues(pkg.liability.validityArea),
        deductible: riskValues(pkg.liability.deductible),
      },
    };
  }

  // Interruption
  if (pkg.interruption) {
    sections.interruption = {
      risks: {
        riskNatural: riskValues(pkg.interruption.riskNatural),
        riskHospital: riskValues(pkg.interruption.riskHospital),
      },
    };
  }

  // Other — riskBasicAssistance is at section level (OtherInsObject lacks selected/value)
  if (pkg.other) {
    sections.other = {
      risks: {
        riskBasicAssistance: riskValues(pkg.other.riskBasicAssistance),
      },
    };
  }

  return sections;
}

// ---- Contract-entity-based section building ----

// Reverse of deductibleValueMap — maps the stored numeric string back to the form's select key.
const reverseDeductibleValueMap: Record<string, string> = Object.fromEntries(
  Object.entries(deductibleValueMap).map(([key, val]) => [String(val), key]),
);

function contractRiskValues(risk?: {
  value?: string;
  selected?: boolean;
}): RiskValues {
  return { enabled: risk?.selected ?? false, payoutValue: risk?.value ?? "" };
}

function contractDeductibleRiskValues(risk?: {
  value?: string;
  selected?: boolean;
}): RiskValues {
  const rawValue = risk?.value ?? "";
  const payoutValue =
    rawValue !== "" ? (reverseDeductibleValueMap[rawValue] ?? rawValue) : "";
  return { enabled: risk?.selected ?? false, payoutValue };
}

export function buildSectionsFromContractEntity(
  entityData: ContractPolicyEntityData,
  calcPkg?: PackageResult,
): Record<string, SectionValues> {
  const sections: Record<string, SectionValues> = {};

  // Buildings
  (entityData.buildings ?? []).forEach((building, index) => {
    sections[`buildings_${index}`] = {
      risks: {
        riskFlexa: contractRiskValues(building.riskFlexa),
        riskNatural: contractRiskValues(building.riskNatural),
        riskFlood: contractRiskValues(building.riskFlood),
        riskTheft: contractRiskValues(building.riskTheft),
        riskVandal: contractRiskValues(building.riskVandal),
        riskGlass: contractRiskValues(building.riskGlass),
        deductible: contractDeductibleRiskValues(building.deductible),
      },
    };
  });

  // Stocks
  if (entityData.stocks) {
    sections.stocks = {
      risks: {
        riskFlexa: contractRiskValues(entityData.stocks.riskFlexa),
        riskNatural: contractRiskValues(entityData.stocks.riskNatural),
        riskFlood: contractRiskValues(entityData.stocks.riskFlood),
        riskTheft: contractRiskValues(entityData.stocks.riskTheft),
        riskVandal: contractRiskValues(entityData.stocks.riskVandal),
        riskTheftMoney: contractRiskValues(entityData.stocks.riskTheftMoney),
        deductible: contractDeductibleRiskValues(entityData.stocks.deductible),
      },
    };
  }

  // Enginery
  if (entityData.enginery) {
    sections.enginery = {
      risks: {
        riskFlexa: contractRiskValues(entityData.enginery.riskFlexa),
        riskNatural: contractRiskValues(entityData.enginery.riskNatural),
        riskFlood: contractRiskValues(entityData.enginery.riskFlood),
        riskTheft: contractRiskValues(entityData.enginery.riskTheft),
        riskVandal: contractRiskValues(entityData.enginery.riskVandal),
        riskSpecial: contractRiskValues(entityData.enginery.riskSpecial),
        deductible: contractDeductibleRiskValues(
          entityData.enginery.deductible,
        ),
        deductibleSpecial: contractDeductibleRiskValues(
          entityData.enginery.deductibleSpecial,
        ),
      },
    };
  }

  // Liability
  if (entityData.liability) {
    sections.liability = {
      risks: {
        riskBasic: contractRiskValues(entityData.liability.riskBasic),
        riskHealthy: contractRiskValues(entityData.liability.riskHealthy),
        riskFinancialHarm: contractRiskValues(
          entityData.liability.riskFinancialHarm,
        ),
        riskNonpecuniaryHarm: contractRiskValues(
          entityData.liability.riskNonpecuniaryHarm,
        ),
        riskRegresInsurance: contractRiskValues(
          entityData.liability.riskRegresInsurance,
        ),
        riskDefectThings: contractRiskValues(
          entityData.liability.riskDefectThings,
        ),
        riskDeferred: contractRiskValues(entityData.liability.riskDeferred),
        riskUsedThings: contractRiskValues(entityData.liability.riskUsedThings),
        // validityArea is stored as a plain "0"|"1" string in the contract, not a risk object
        validityArea: {
          enabled: false,
          payoutValue: entityData.liability.validityArea ?? "",
        },
        deductible: contractDeductibleRiskValues(
          entityData.liability.deductible,
        ),
      },
    };
  }

  // Interruption
  if (entityData.interruption) {
    sections.interruption = {
      risks: {
        riskNatural: contractRiskValues(entityData.interruption.riskNatural),
        riskHospital: contractRiskValues(entityData.interruption.riskHospital),
      },
    };
  }

  // 'other' is not persisted in contract entities — use calculation values when available
  if (calcPkg?.other) {
    sections.other = {
      risks: {
        riskBasicAssistance: riskValues(calcPkg.other.riskBasicAssistance),
      },
    };
  }

  return sections;
}

export function getSelectedTierFromContract(
  contract: BusinessInsuranceContract,
): PackageTier | null {
  if (contract.businessInsurancePolicyEssential?.entityData?.selected)
    return "essential";
  if (contract.businessInsurancePolicySmart?.entityData?.selected)
    return "smart";
  if (contract.businessInsurancePolicyPremium?.entityData?.selected)
    return "premium";
  return null;
}

// Assembles the full form default values.
// When contract entities exist (returning user), reads from them to restore saved selections.
// Falls back to calculation data on first visit (entities not yet created).
export function buildDefaultValues(
  packagesByTier: PackagesByTier,
  contract: BusinessInsuranceContract,
): QuoteFormShape {
  const packageTier: PackageTier =
    getSelectedTierFromContract(contract) ?? "premium";

  const buildCoverType = (
    entityData: ContractPolicyEntityData | undefined,
    calcPkg: PackageResult,
  ): Record<string, SectionValues> => {
    if (!entityData) return buildSections(calcPkg);
    return buildSectionsFromContractEntity(entityData, calcPkg);
  };

  return {
    packageTier,
    coverTypes: {
      essential: buildCoverType(
        contract.businessInsurancePolicyEssential?.entityData,
        packagesByTier.essential,
      ),
      smart: buildCoverType(
        contract.businessInsurancePolicySmart?.entityData,
        packagesByTier.smart,
      ),
      premium: buildCoverType(
        contract.businessInsurancePolicyPremium?.entityData,
        packagesByTier.premium,
      ),
    },
  };
}

import type { CalculationRequest } from "../../../../query/quoteApiTypes.ts";
import type { RiskValues, SectionValues } from "./quoteForm.types.ts";

function toRisk(
  risk: RiskValues | undefined,
): { selected: string; value?: string } | undefined {
  if (!risk) return undefined;
  return {
    selected: risk.enabled ? "1" : "0",
    ...(risk.payoutValue ? { value: risk.payoutValue } : {}),
  };
}

function toDeductible(risk: RiskValues | undefined) {
  if (!risk || !risk.payoutValue) return undefined;
  return { value: risk.payoutValue, selected: risk.enabled ? "1" : "0" };
}

// Merges the user's form section values (risk toggles/amounts) into the base EP calculation request.
export function mergeFormSections(
  request: CalculationRequest,
  sections: Record<string, SectionValues>,
): CalculationRequest {
  const buildingEntries = Object.entries(sections)
    .filter(([key]) => key.startsWith("buildings_"))
    .sort(
      ([a], [b]) =>
        parseInt(a.split("_")[1], 10) - parseInt(b.split("_")[1], 10),
    );

  buildingEntries.forEach(([, section], i) => {
    const insObj = request.buildings?.insObject[i];
    if (!insObj) return;
    Object.assign(insObj, {
      riskNatural: toRisk(section.risks.riskNatural),
      riskVandal: toRisk(section.risks.riskVandal),
      riskTheft: toRisk(section.risks.riskTheft),
      riskFlood: toRisk(section.risks.riskFlood),
      riskGlass: toRisk(section.risks.riskGlass),
      deductible: toDeductible(section.risks.deductible),
    });
  });

  const stocksInsObj = request.stocks?.insObject[0];
  const stocksSection = sections.stocks;
  if (stocksInsObj && stocksSection) {
    Object.assign(stocksInsObj, {
      riskNatural: toRisk(stocksSection.risks.riskNatural),
      riskVandal: toRisk(stocksSection.risks.riskVandal),
      riskFlood: toRisk(stocksSection.risks.riskFlood),
      riskTheft: toRisk(stocksSection.risks.riskTheft),
      riskTheftMoney: toRisk(stocksSection.risks.riskTheftMoney),
      deductible: toDeductible(stocksSection.risks.deductible),
    });
  }

  const engineryInsObj = request.enginery?.insObject[0];
  const enginerySection = sections.enginery;
  if (engineryInsObj && enginerySection) {
    Object.assign(engineryInsObj, {
      riskNatural: toRisk(enginerySection.risks.riskNatural),
      riskVandal: toRisk(enginerySection.risks.riskVandal),
      riskTheft: toRisk(enginerySection.risks.riskTheft),
      riskFlood: toRisk(enginerySection.risks.riskFlood),
      riskSpecial: toRisk(enginerySection.risks.riskSpecial),
      deductible: toDeductible(enginerySection.risks.deductible),
      deductibleSpecial: toDeductible(enginerySection.risks.deductibleSpecial),
    });
  }

  const liabilityInsObj = request.liability?.insObject[0];
  const liabilitySection = sections.liability;
  if (liabilityInsObj && liabilitySection) {
    const validityArea = liabilitySection.risks.validityArea;
    Object.assign(liabilityInsObj, {
      riskFinancialHarm: toRisk(liabilitySection.risks.riskFinancialHarm),
      riskNonpecuniaryHarm: toRisk(liabilitySection.risks.riskNonpecuniaryHarm),
      riskDeferred: toRisk(liabilitySection.risks.riskDeferred),
      riskRegresInsurance: toRisk(liabilitySection.risks.riskRegresInsurance),
      riskDefectThings: toRisk(liabilitySection.risks.riskDefectThings),
      riskHealthy: toRisk(liabilitySection.risks.riskHealthy),
      riskBasic: toRisk(liabilitySection.risks.riskBasic),
      riskUsedThings: toRisk(liabilitySection.risks.riskUsedThings),
      deductible: toDeductible(liabilitySection.risks.deductible),
      validityArea: validityArea?.payoutValue
        ? {
            selected: validityArea.enabled ? "1" : "0",
            value: validityArea.payoutValue,
          }
        : undefined,
    });
  }

  const interruptionInsObj = request.interruption?.insObject[0];
  const interruptionSection = sections.interruption;
  if (interruptionInsObj && interruptionSection) {
    Object.assign(interruptionInsObj, {
      riskNatural: toRisk(interruptionSection.risks.riskNatural),
      riskHospital: toRisk(interruptionSection.risks.riskHospital),
    });
  }

  const otherInsObj = request.other?.insObject[0];
  const otherSection = sections.other;
  if (otherInsObj && otherSection) {
    const assist = otherSection.risks.riskBasicAssistance;
    Object.assign(otherInsObj, {
      riskBasicAssistance: assist
        ? { selected: assist.enabled ? "1" : "0", value: assist.payoutValue }
        : undefined,
    });
  }

  return request;
}

