import { isNotEmpty } from "ramda";

import { transactionCategoryEnum } from "@dfp/bw-isomorphic-enums";
import {
  type ActiveButtonsConfig,
  type CategoryConfig,
  MultiCheckboxFilterDetail,
  TableFilters,
  getFilterCountsByCategory,
} from "@dfp/bw-react-filtered-table";
import { useEnum } from "@dfp/react-enums";
import { getFormShape, withForm } from "@dfp/react-form";
import {
  IconBank,
  IconBankNote01,
  IconBuilding05,
  IconTag01,
} from "@dfp/react-icons";

import { useTT } from "../../../useTT.ts";
import type { FilteringArray } from "./AccountFiltersProvider.tsx";
import { ActiveFilterButton } from "./ActiveFilterButton.tsx";
import {
  type FilterCategory,
  accountTypes,
  filterCategories,
  filteringAttrsByCategory,
} from "./consts.ts";
import {
  CompanyFilterDetail,
  CurrencyFilterDetail,
} from "./filter-inputs/index.ts";
import type { AccountType, FormShape } from "./types.ts";
import { useResetFilters } from "./useResetFilters.ts";

export const AccountsFilters = withForm({
  defaultValues: getFormShape<FormShape>(),
  render: function Render({ form }) {
    const { tt } = useTT();
    const { enumTranslatedOptions } = useEnum(transactionCategoryEnum);

    const categoriesConfig: CategoryConfig<FilterCategory>[] = [
      {
        key: "companies",
        menuLabel: tt("accountFilters.companies.menuLabel"),
        icon: <IconBuilding05 />,
        isActiveFilter: (currentFiltering) =>
          (currentFiltering as FilteringArray).some((filter) =>
            filteringAttrsByCategory.companies.some((attr) =>
              filter.filteringAttribute.includes(attr),
            ),
          ),
        renderDetail: () => <CompanyFilterDetail form={form} />,
      },
      {
        key: "currencies",
        menuLabel: tt("accountFilters.currencies.menuLabel"),
        icon: <IconBankNote01 />,
        isActiveFilter: (currentFiltering) =>
          (currentFiltering as FilteringArray).some((filter) =>
            filteringAttrsByCategory.currencies.some((attr) =>
              filter.filteringAttribute.includes(attr),
            ),
          ),
        renderDetail: () => <CurrencyFilterDetail form={form} />,
      },
      {
        key: "categories",
        menuLabel: tt("accountFilters.categories.menuLabel"),
        icon: <IconTag01 />,
        isActiveFilter: (currentFiltering) =>
          (currentFiltering as FilteringArray).some((filter) =>
            filteringAttrsByCategory.categories.some((attr) =>
              filter.filteringAttribute.includes(attr),
            ),
          ),
        renderDetail: () => (
          <MultiCheckboxFilterDetail
            name="categories"
            form={form}
            options={enumTranslatedOptions.map((category) => ({
              value: category.value,
              label: category.label,
              textLabel: category.label,
            }))}
            title={tt("accountFilters.categories.title")}
            selectAllLabel={tt("accountFilters.categories.selectAll")}
            selectNoneLabel={tt("accountFilters.categories.selectNone")}
          />
        ),
      },
      {
        key: "accountTypes",
        menuLabel: tt("accountFilters.accountTypes.menuLabel"),
        icon: <IconBank />,
        isActiveFilter: (currentFiltering) => {
          // if both account types are selected, we actually don't pass any filtering as needed by API
          // so we need to check if the form value is not empty
          const value = form.getFieldValue("accountTypes");

          return (
            (currentFiltering as FilteringArray).some((filter) =>
              filteringAttrsByCategory.accountTypes.some((attr) =>
                filter.filteringAttribute.includes(attr),
              ),
            ) || isNotEmpty(value)
          );
        },
        renderDetail: () => (
          <MultiCheckboxFilterDetail
            name="accountTypes"
            form={form}
            options={accountTypes.map((value: AccountType) => ({
              value,
              label: tt(`accountFilters.accountTypes.options.${value}`),
              textLabel: tt(`accountFilters.accountTypes.options.${value}`),
            }))}
            title={tt("accountFilters.accountTypes.title")}
            selectAllLabel={tt("accountFilters.accountTypes.selectAll")}
            selectNoneLabel={tt("accountFilters.accountTypes.selectNone")}
          />
        ),
      },
    ];

    const activeButtonsConfig: ActiveButtonsConfig<FilterCategory, FormShape> =
      {
        categoriesOrder: [...filterCategories] as FilterCategory[],
        staticCategories: [
          "currencies",
          "companies",
          "categories",
          "accountTypes",
        ],
        // all categories are always visible in account filters
        isCategoryVisible: () => true,
        getFilterCountsByCategory: (currentFiltering) =>
          getFilterCountsByCategory(
            currentFiltering as FilteringArray,
            filteringAttrsByCategory,
          ),
        renderButton: ({ category, label, filtersCount }) => (
          <ActiveFilterButton
            category={category}
            label={label}
            filtersCount={filtersCount}
            form={form}
          />
        ),
      };

    const onResetFilters = useResetFilters(form);

    return (
      <TableFilters
        form={form}
        categories={categoriesConfig}
        defaultCategory="companies"
        activeButtonsConfig={activeButtonsConfig}
        onResetFilters={onResetFilters}
      />
    );
  },
});

