import {
  Card,
  CardHeader,
  Checkbox,
  FormControlLabel,
  FormHelperText,
  Stack,
} from "@mui/material";
import { useStore } from "@tanstack/react-form";
import { useEffect } from "react";

import { CardContent } from "@dfp/react-components";
import { useAppForm, validateRequired } from "@dfp/react-form";

import { useGetBusinessInsuranceRules } from "../../../../query/index.ts";
import { useTT } from "../../../../useTT.ts";
import { ConfirmPreContractualInfoLabel } from "./ConfirmPreContractualInfoLabel.tsx";
import { PaymentSummaryCard } from "./PaymentSummaryCard.tsx";
import { type ContractDetailsFormShape } from "./contractDetailsForm.types.ts";
import { useContractCalculation } from "./useContractCalculation.ts";

type StringRuleAttr = {
  stringParams?: { pattern?: { source: string; flags?: string } };
};

type Props = {
  defaultValues: ContractDetailsFormShape;
  onSubmit: (values: ContractDetailsFormShape) => Promise<void>;
};

export function ContractDetailsForm({ defaultValues, onSubmit }: Props) {
  const { tt, language } = useTT();
  const { data: rules } = useGetBusinessInsuranceRules();
  const phonePattern = (
    rules?.entitiesRules?.contractDetails?.onEntity?.attrs as
      | Record<string, StringRuleAttr>
      | undefined
  )?.phoneNumber?.stringParams?.pattern;
  const {
    trigger: triggerCalculation,
    calculationResult,
    isPending,
  } = useContractCalculation();

  const form = useAppForm({
    defaultValues,
    onSubmit: ({ value }) => onSubmit(value),
    listeners: {
      onMount: ({ formApi }) => triggerCalculation(formApi.state.values),
      onChange: ({ formApi }) => triggerCalculation(formApi.state.values),
    },
  });

  const billingCycle =
    useStore(form.store, (state) => state.values.billingCycle) ?? "annually";
  const companyType =
    useStore(form.store, (state) => state.values.companyType) ?? "legalEntity";
  const noIdentificationNumber = useStore(
    form.store,
    (state) => state.values.noIdentificationNumber,
  );

  const isSoleTraderOrIndividual = ["soleTrader", "individual"].includes(
    companyType,
  );

  // https://github.com/TanStack/form/issues/1133
  useEffect(() => {
    if (!isSoleTraderOrIndividual) {
      form.deleteField("firstName");
      form.deleteField("lastName");
      form.deleteField("identificationNumber");
      form.deleteField("noIdentificationNumber");
    }
  }, [isSoleTraderOrIndividual, form]);

  useEffect(() => {
    if (noIdentificationNumber) {
      form.deleteField("identificationNumber");
    }
  }, [noIdentificationNumber, form]);

  const billingCycleOptions = [
    {
      value: "annually",
      label: tt("insurance.contractDetails.billingCycle.annually"),
    },
    {
      value: "semiAnnually",
      label: tt("insurance.contractDetails.billingCycle.semiAnnually"),
    },
    {
      value: "quarterly",
      label: tt("insurance.contractDetails.billingCycle.quarterly"),
    },
  ];

  const companyTypeOptions = [
    {
      value: "legalEntity",
      label: tt("insurance.contractDetails.companyType.legalEntity"),
    },
    {
      value: "soleTrader",
      label: tt("insurance.contractDetails.companyType.soleTrader"),
    },
    {
      value: "individual",
      label: tt("insurance.contractDetails.companyType.individual"),
    },
  ];

  const installmentValue = parseFloat(
    calculationResult?.installmentValue ?? "0",
  );

  return (
    <form
      onSubmit={(event) => {
        event.preventDefault();
        event.stopPropagation();
        form.handleSubmit();
      }}
    >
      <form.AppForm>
        <Stack sx={{ gap: 4 }}>
          <Card>
            <CardHeader title={tt("insurance.contractDetails.title")} />
            <CardContent>
              <Stack sx={{ gap: 2, p: 3 }}>
                {/* Effective date */}
                <form.AppField
                  name="effectiveDate"
                  validators={validateRequired()}
                >
                  {(field) => (
                    <field.DatePicker
                      label={tt("insurance.contractDetails.effectiveDate")}
                      placeholder={tt(
                        "insurance.contractDetails.effectiveDatePlaceholder",
                      )}
                      language={language}
                      required
                    />
                  )}
                </form.AppField>

                {/* For an indefinite period */}
                <form.AppField name="indefinitePeriod">
                  {(field) => (
                    <field.Checkbox
                      label={tt(
                        "insurance.contractDetails.forIndefinitePeriod",
                      )}
                      hideOptionalLabel
                    />
                  )}
                </form.AppField>

                {/* Billing cycle + Payment info */}
                <Stack
                  sx={{ flexDirection: { xs: "column", md: "row" }, gap: 2 }}
                >
                  <Stack sx={{ flex: 1 }}>
                    <form.AppField
                      name="billingCycle"
                      validators={validateRequired()}
                    >
                      {(field) => (
                        <field.Radio
                          required
                          label={tt(
                            "insurance.contractDetails.billingCycle.label",
                          )}
                          options={billingCycleOptions}
                        />
                      )}
                    </form.AppField>
                  </Stack>

                  <Stack sx={{ flex: 1, mr: { xs: 0, md: 2 } }}>
                    <PaymentSummaryCard
                      installmentValue={installmentValue}
                      billingCycle={billingCycle}
                      isLoading={isPending}
                    />
                  </Stack>
                </Stack>

                {/* Company type */}
                <form.AppField
                  name="companyType"
                  validators={validateRequired()}
                >
                  {(field) => (
                    <field.Radio
                      required
                      label={tt("insurance.contractDetails.companyType.label")}
                      options={companyTypeOptions}
                    />
                  )}
                </form.AppField>

                {/* Company registration number */}
                {companyType !== "individual" && (
                  <form.AppField name="companyName">
                    {(field) => (
                      <field.Text
                        label={tt(
                          "insurance.contractDetails.companyRegistrationNumber",
                        )}
                        readOnly
                      />
                    )}
                  </form.AppField>
                )}

                {/* First name - visible only for soleTrader and individual */}
                {isSoleTraderOrIndividual && (
                  <form.AppField
                    name="firstName"
                    validators={validateRequired()}
                  >
                    {(field) => (
                      <field.Text
                        label={tt("insurance.contractDetails.firstName")}
                        required
                      />
                    )}
                  </form.AppField>
                )}

                {/* Last name - visible only for soleTrader and individual */}
                {isSoleTraderOrIndividual && (
                  <form.AppField
                    name="lastName"
                    validators={validateRequired()}
                  >
                    {(field) => (
                      <field.Text
                        label={tt("insurance.contractDetails.lastName")}
                        required
                      />
                    )}
                  </form.AppField>
                )}

                {/* ID number - visible only for soleTrader and individual */}
                {isSoleTraderOrIndividual && (
                  <>
                    {!noIdentificationNumber && (
                      <form.AppField
                        name="identificationNumber"
                        validators={{
                          onChange: ({ value }) => {
                            if (value?.trim().length > 0) {
                              return undefined;
                            }
                            return tt(
                              "insurance.contractDetails.idNumberRequired",
                            );
                          },
                        }}
                      >
                        {(field) => (
                          <field.Text
                            label={tt("insurance.contractDetails.idNumber")}
                            hideOptionalLabel
                          />
                        )}
                      </form.AppField>
                    )}

                    {/* Checkbox for no ID number */}
                    <form.AppField name="noIdentificationNumber">
                      {(field) => (
                        <field.Checkbox
                          label={tt("insurance.contractDetails.noIdNumber")}
                          hideOptionalLabel
                        />
                      )}
                    </form.AppField>
                  </>
                )}

                {/* Phone number */}
                <form.AppField
                  name="phoneNumber"
                  validators={{
                    onChange: ({ value }) => {
                      const requiredError = validateRequired().onChange({
                        value,
                      });
                      if (requiredError) return requiredError;
                      if (
                        phonePattern &&
                        !new RegExp(
                          phonePattern.source,
                          phonePattern.flags,
                        ).test(value)
                      ) {
                        return tt(
                          "insurance.contractDetails.phoneNumberInvalid",
                        );
                      }
                      return null;
                    },
                  }}
                >
                  {(field) => (
                    <field.PhoneInput
                      label={tt("insurance.contractDetails.phoneNumber")}
                      required
                    />
                  )}
                </form.AppField>

                {/* Email */}
                <form.AppField name="email" validators={validateRequired()}>
                  {(field) => (
                    <field.Text
                      label={tt("insurance.contractDetails.email")}
                      required
                    />
                  )}
                </form.AppField>

                {/* Confirm pre-contractual info */}
                <form.AppField
                  name="confirmationOfLegality"
                  validators={{
                    onSubmit: ({ value }) =>
                      value
                        ? undefined
                        : tt(
                            "insurance.contractDetails.confirmPreContractualInfoError",
                          ),
                  }}
                >
                  {(field) => {
                    const errorMessage = (field.state.meta.errors as string[])
                      .filter(Boolean)
                      .join(" ");
                    return (
                      <>
                        <FormControlLabel
                          control={
                            <Checkbox
                              checked={field.state.value ?? false}
                              onBlur={() => field.handleBlur()}
                              onChange={(e) =>
                                field.handleChange(e.target.checked)
                              }
                              sx={{ mt: -1 }}
                            />
                          }
                          label={<ConfirmPreContractualInfoLabel />}
                          sx={{ alignItems: "flex-start" }}
                        />
                        {errorMessage && (
                          <FormHelperText error>{errorMessage}</FormHelperText>
                        )}
                      </>
                    );
                  }}
                </form.AppField>
              </Stack>
            </CardContent>
          </Card>

          <form.Submit disabledOnPristine={false}>
            {tt("insurance.buttonSubmit")}
          </form.Submit>
        </Stack>
      </form.AppForm>
    </form>
  );
}

import { Button, Stack, Typography } from "@mui/material";
import { useNavigate } from "react-router";

import { useCompanyDataDetail } from "@dfp/bw-react-company";
import { makeRoute, pathRoutes } from "@dfp/bw-react-routing";
import { useUserClaims } from "@dfp/bw-react-user-context";
import { useCommonTranslation } from "@dfp/react-common-translation";
import { useAppForm, validateRequired } from "@dfp/react-form";

import {
  useCreateBusinessInsuranceEntity,
  useGetBusinessInsurance,
  useGetBusinessInsuranceRules,
  useUpdateBusinessInsuranceEntity,
} from "../../../../query/index.ts";
import { useTT } from "../../../../useTT.ts";

type IndividualOfferFormValues = {
  ic: string;
  companyName: string;
  address: string;
  phoneNumber: string;
  email: string;
};

type StringRuleAttr = {
  stringParams?: { pattern?: { source: string; flags?: string } };
};

type Props = {
  handleClose: () => void;
};

export function IndividualOfferForm({ handleClose }: Props) {
  const { tt } = useTT();
  const { commonTT } = useCommonTranslation();
  const navigate = useNavigate();

  const { email: userEmail, phoneNumber: userPhone } = useUserClaims();
  const { data: contract } = useGetBusinessInsurance();
  const { mutateAsync: updateEntity } = useUpdateBusinessInsuranceEntity();
  const { mutateAsync: createEntity } = useCreateBusinessInsuranceEntity();
  const { data: rules } = useGetBusinessInsuranceRules();

  const individualOfferAttrs = rules?.entitiesRules?.individualOffer?.onEntity
    ?.attrs as Record<string, StringRuleAttr> | undefined;
  const icPattern = individualOfferAttrs?.ic?.stringParams?.pattern;
  const phonePattern = individualOfferAttrs?.phoneNumber?.stringParams?.pattern;

  const companyId = contract?.partyRoleRef?.entityData?.documentId ?? "";
  const { data: companyData } = useCompanyDataDetail(companyId);

  const addressString = [
    companyData?.address?.street,
    companyData?.address?.zipCode,
    companyData?.address?.city,
  ]
    .filter(Boolean)
    .join(", ");

  const defaultValues: IndividualOfferFormValues = {
    ic: companyData?.registrationNumber ?? "",
    companyName: companyData?.name || companyData?.legalName || "",
    address: addressString,
    phoneNumber: userPhone ?? "",
    email: userEmail ?? "",
  };

  const form = useAppForm({
    defaultValues,
    onSubmit: async ({ value: entityData }) => {
      if (!contract) return;

      if (!contract.individualOffer?.entityData) {
        await createEntity({
          contract,
          createEntity: { individualOffer: { entityData } },
        });
      } else {
        await updateEntity({
          contract,
          updateEntity: { individualOffer: { entityData } },
        });
      }

      handleClose();
      navigate(makeRoute(pathRoutes.marketplace));
    },
  });

  return (
    <form
      onSubmit={(event) => {
        event.preventDefault();
        event.stopPropagation();
        form.handleSubmit();
      }}
    >
      <form.AppForm>
        <Stack sx={{ gap: 2, pb: 3 }}>
          <Typography variant="body2">
            {tt("insurance.individualOffer.description")}
          </Typography>

          <form.AppField
            name="ic"
            validators={{
              onChange: ({ value }) => {
                const requiredError = validateRequired().onChange({ value });
                if (requiredError) return requiredError;
                if (
                  icPattern &&
                  !new RegExp(icPattern.source, icPattern.flags).test(value)
                ) {
                  return tt("insurance.individualOffer.icoInvalid");
                }
                return null;
              },
            }}
          >
            {(field) => (
              <field.Text
                label={tt("insurance.individualOffer.ico")}
                required
              />
            )}
          </form.AppField>

          <form.AppField name="companyName" validators={validateRequired()}>
            {(field) => (
              <field.Text
                label={tt("insurance.individualOffer.companyName")}
                required
              />
            )}
          </form.AppField>

          <form.AppField name="address" validators={validateRequired()}>
            {(field) => (
              <field.Text
                label={tt("insurance.individualOffer.companyAddress")}
                required
              />
            )}
          </form.AppField>

          <form.AppField
            name="phoneNumber"
            validators={{
              onChange: ({ value }) => {
                const requiredError = validateRequired().onChange({ value });
                if (requiredError) return requiredError;
                if (
                  phonePattern &&
                  !new RegExp(phonePattern.source, phonePattern.flags).test(
                    value,
                  )
                ) {
                  return tt("insurance.individualOffer.phoneNumberInvalid");
                }
                return null;
              },
            }}
          >
            {(field) => (
              <field.PhoneInput
                label={tt("insurance.individualOffer.phoneNumber")}
                required
              />
            )}
          </form.AppField>

          <form.AppField name="email" validators={validateRequired()}>
            {(field) => (
              <field.Text
                label={tt("insurance.individualOffer.email")}
                required
              />
            )}
          </form.AppField>

          <Stack
            sx={{ flexDirection: "row", justifyContent: "flex-end", gap: 1 }}
          >
            <Button color="secondary" onClick={handleClose}>
              {commonTT("Button.cancel")}
            </Button>
            <form.Submit disabledOnPristine={false}>
              {tt("insurance.individualOffer.submit")}
            </form.Submit>
          </Stack>
        </Stack>
      </form.AppForm>
    </form>
  );
}

import { Box, Button, Stack } from "@mui/material";
import { useState } from "react";

import {
  type TransactionCategory,
  transactionCategoryEnum,
} from "@dfp/bw-isomorphic-enums";
import { useCommonTranslation } from "@dfp/react-common-translation";
import { FieldRadio, FieldSelect } from "@dfp/react-components";
import type { FieldChangeEvent } from "@dfp/react-components";
import { useEnum } from "@dfp/react-enums";

import type { CategoryUpdateData, UpdateOption } from "../types.ts";
import { useTT } from "../useTT.ts";

type AccountDetailCategoryChangeContentProps = {
  onClose: () => void;
  onCategoryChange: (data: CategoryUpdateData) => void;
};

export function AccountDetailCategoryChangeContent({
  onClose,
  onCategoryChange,
}: AccountDetailCategoryChangeContentProps) {
  const { tt } = useTT();
  const { commonTT } = useCommonTranslation();
  const { enumTranslatedOptions } = useEnum(transactionCategoryEnum);
  const [selectedCategory, setSelectedCategory] =
    useState<TransactionCategory>("INCOME");
  const [selectedUpdateOption, setSelectedUpdateOption] =
    useState<UpdateOption>("thisFuture");

  const updateOptions = [
    {
      value: "thisFuture",
      label: tt("accountDetail.categoryChange.updateOptions.thisFuture.label"),
      description: tt(
        "accountDetail.categoryChange.updateOptions.thisFuture.description",
      ),
    },
    {
      value: "allTransactions",
      label: tt(
        "accountDetail.categoryChange.updateOptions.allTransactions.label",
      ),
      description: tt(
        "accountDetail.categoryChange.updateOptions.allTransactions.description",
      ),
    },
  ];

  const handleCategorySelectChange = (event: FieldChangeEvent<string>) => {
    if (event.target.value) {
      setSelectedCategory(event.target.value as TransactionCategory);
    }
  };

  const handleUpdateOptionChange = (event: FieldChangeEvent<string>) => {
    if (event.target.value) {
      setSelectedUpdateOption(event.target.value as UpdateOption);
    }
  };

