import { Box, Button, Stack } from "@mui/material";
import { useState } from "react";

import {
  type TransactionCategory,
  transactionCategoryEnum,
} from "@dfp/bw-isomorphic-enums";
import { useCommonTranslation } from "@dfp/react-common-translation";
import { FieldRadio, FieldSelect } from "@dfp/react-components";
import type { FieldChangeEvent } from "@dfp/react-components";
import { useEnum } from "@dfp/react-enums";

import type { CategoryUpdateData, UpdateOption } from "../../types.ts";
import { useTT } from "../../useTT.ts";

type TransactionsCategoryChangeDetailContentProps = {
  onClose: () => void;
  transactionIds: string[];
  onCategoryChange: (data: CategoryUpdateData) => void;
  hasAllCounterBankAccountRefs: boolean;
};

export function TransactionsCategoryChangeDetailContent({
  onClose,
  transactionIds,
  onCategoryChange,
  hasAllCounterBankAccountRefs,
}: TransactionsCategoryChangeDetailContentProps) {
  const { tt } = useTT();
  const { commonTT } = useCommonTranslation();
  const { enumTranslatedOptions } = useEnum(transactionCategoryEnum);
  const [selectedCategory, setSelectedCategory] =
    useState<TransactionCategory>("INCOME");
  const [selectedUpdateOption, setSelectedUpdateOption] =
    useState<UpdateOption>("thisOnly");

  const allUpdateOptions = [
    {
      value: "thisOnly",
      label: tt("transactionsCategoryChange.updateOptions.thisOnly.label"),
      description: tt(
        "transactionsCategoryChange.updateOptions.thisOnly.description",
      ),
    },
    {
      value: "thisFuture",
      label: tt("transactionsCategoryChange.updateOptions.thisFuture.label"),
      description: tt(
        "transactionsCategoryChange.updateOptions.thisFuture.description",
      ),
    },
    {
      value: "allTransactions",
      label: tt(
        "transactionsCategoryChange.updateOptions.allTransactions.label",
      ),
      description: tt(
        "transactionsCategoryChange.updateOptions.allTransactions.description",
      ),
    },
  ];

  const updateOptions = hasAllCounterBankAccountRefs
    ? allUpdateOptions
    : allUpdateOptions.filter((option) => option.value === "thisOnly");

  const handleCategorySelectChange = (event: FieldChangeEvent<string>) => {
    if (event.target.value) {
      setSelectedCategory(event.target.value as TransactionCategory);
    }
  };

  const handleUpdateOptionChange = (event: FieldChangeEvent<string>) => {
    if (event.target.value) {
      setSelectedUpdateOption(event.target.value as UpdateOption);
    }
  };

  const handleCategorySubmit = () => {
    const updateData = {
      transactionIds,
      selectedCategory,
      selectedUpdateOption,
    };
    onCategoryChange(updateData);
  };

  return (
    <Stack
      sx={{
        gap: 3,
        pb: 4,
      }}
    >
      <FieldSelect
        name="category"
        label={tt("transactionsCategoryChange.categoryLabel")}
        value={selectedCategory}
        options={enumTranslatedOptions.filter(
          (category) => category.valueUsage === "CanBeEntered",
        )}
        onChange={handleCategorySelectChange}
        required
      />
      <FieldRadio
        name="updateOption"
        label={tt("transactionsCategoryChange.updateOptionsLabel")}
        value={selectedUpdateOption}
        options={updateOptions}
        onChange={handleUpdateOptionChange}
        variant="card"
        required
      />
      <Box sx={{ display: "flex", gap: 1, justifyContent: "flex-end" }}>
        <Button
          onClick={onClose}
          variant="contained"
          color="secondary"
          size="medium"
        >
          {commonTT("Button.cancel")}
        </Button>
        <Button
          onClick={handleCategorySubmit}
          variant="contained"
          color="primary"
          size="medium"
        >
          {commonTT("Button.save")}
        </Button>
      </Box>
    </Stack>
  );
}

