type Props = {
  data: MergeDataType;
};

export function EmailDoesNotMatch({ data }: Props) {
  const { tt } = useTT();
  const { t: tTrans } = useTranslation(projectName);
  const translatedDate = useTranslatedDate();

  const dateOfBirthNewParty = data.newParty.dateOfBirth
    ? translatedDate(data.newParty.dateOfBirth, {})
    : null;
  const alertTitleKey = (() => {
    if (data.nameMismatch && data.dateOfBirthMismatch) {
      return "alertTitleNameAndDoBChange";
    } else if (data.nameMismatch) {
      return "alertTitleNameChange";
    } else if (data.dateOfBirthMismatch) {
      return "alertTitleDoBChange";
    } else {
      return "alertTitle";
    }
  })();

  return (
    <Stack sx={{ gap: 3 }}>
      <Typography variant="body2">
        <TTrans
          i18nKey={
            isEmpty(data.newParty.companyName)
              ? "emailDoesNotMatch.descriptionWithoutCompany"
              : "emailDoesNotMatch.description"
          }
          tt={tTrans}
          values={{
            companyName: data.newParty.companyName,
            email: data.existingParty.email,
          }}
        />
      </Typography>

      <Alert severity="info">
        <AlertTitle>
          {tt(`emailDoesNotMatch.${alertTitleKey}`, {
            name: data.newParty.name,
            ...(dateOfBirthNewParty
              ? { dateOfBirth: dateOfBirthNewParty }
              : {}),
          })}
