        {tt("emailDoesNotMatch.alertDescription")}
      </Alert>

      <Sections>
        <Section title={tt("emailDoesNotMatch.currentPartyTitle")}>
          <SectionCard title={tt("emailDoesNotMatch.currentPartySubtitle")}>
            <PartyData partyData={data.newParty} />
