        </Section>
        <Section title={tt("emailDoesNotMatch.otherPartyTitle")}>
          <SectionCard title={tt("emailDoesNotMatch.otherPartySubtitle")}>
            <PartyData
              partyData={data.existingParty}
              nameMismatch={data.nameMismatch}
              dateOfBirthMismatch={data.dateOfBirthMismatch}
            />
          </SectionCard>
        </Section>
        <Section title={tt("emailDoesNotMatch.changesTitle")}>
          {(data.nameMismatch || data.dateOfBirthMismatch) && (
            <SectionCard title={tt("emailDoesNotMatch.otherPartySubtitle")}>
              <Typography variant="body2">
                {tt("emailDoesNotMatch.changesDescription1")}
              </Typography>
              <KeyValueContainer stacked>
                {data.nameMismatch && (
                  <KVItem
                    keyValue={tt("partyDataContainer.name")}
                    value={
                      <ValueChange
                        oldValue={data.existingParty.name}
                        newValue={data.newParty.name}
                      />
                    }
                  />
                )}
                {data.dateOfBirthMismatch && (
                  <KVItem
                    keyValue={tt("partyDataContainer.dateOfBirth")}
                    value={
