          <SectionCard title={tt("emailDoesNotMatch.changesSubtitle")}>
            <Stack gap={1}>
              {data.dateOfBirthMismatch || data.nameMismatch ? (
                <Typography variant="body2">
                  {tt("emailDoesNotMatch.changesDescription2")}
