import { execFileSync } from 'node:child_process';
import { existsSync, mkdirSync, rmSync, writeFileSync, readFileSync } from 'node:fs';
import path from 'node:path';
import os from 'node:os';

function parseArgs(argv) {
  const args = { scope: null, outDir: 'docs/analysis', jscpdArgs: [], fallowArgs: [] };
  const rest = [];
  let passthrough = false;
  for (let i = 0; i < argv.length; i++) {
    const a = argv[i];
    if (passthrough) {
      rest.push(a);
      continue;
    }
    if (a === '--') {
      passthrough = true;
      continue;
    }
    if (a === '--scope') {
      args.scope = argv[++i];
      continue;
    }
    if (a === '--out-dir') {
      args.outDir = argv[++i];
      continue;
    }
    if (a === '--jscpd-args') {
      args.jscpdArgs = argv[++i].split(' ').filter(Boolean);
      continue;
    }
    if (a === '--fallow-args') {
      args.fallowArgs = argv[++i].split(' ').filter(Boolean);
      continue;
    }
    if (!args.scope) args.scope = a;
    else rest.push(a);
  }
  args.passthrough = rest;
  return args;
}

function run(cmd, args, opts = {}) {
  return execFileSync(cmd, args, {
    encoding: 'utf8',
    stdio: ['ignore', 'pipe', 'pipe'],
    maxBuffer: 128 * 1024 * 1024,
    ...opts,
  });
}

function assertBwReactScope(scope) {
  if (scope && !scope.includes('bw-react')) {
    throw new Error(`Scope must contain "bw-react". Got: ${scope}`);
  }
}

function main() {
  const args = parseArgs(process.argv.slice(2));
  const scope = args.scope || '';
  assertBwReactScope(scope || 'bw-react');

  const repoRoot = run('git', ['rev-parse', '--show-toplevel']).trim();
  const tmpRoot = path.join(os.tmpdir(), 'pi-duplication-auditor');
  mkdirSync(tmpRoot, { recursive: true });
  const workDir = path.join(tmpRoot, String(Date.now()));
  mkdirSync(workDir, { recursive: true });
  const outDir = path.resolve(repoRoot, args.outDir);
  mkdirSync(outDir, { recursive: true });

  const scopeArg = scope || 'bw-react';
  const scopeLabel = scopeArg.replace(/[^a-zA-Z0-9._-]+/g, '_');
  const jscpdOut = path.join(outDir, `jscpd-${scopeLabel}.json`);
  const fallowOut = path.join(outDir, `fallow-${scopeLabel}.json`);
  const summaryOut = path.join(outDir, `duplication-summary-${scopeLabel}.md`);

  try {
    // jscpd: scope by path if provided, otherwise repo-wide bw-react focus via git-ignored file list is left to the user.
    const jscpdCmd = ['jscpd', '--reporters', 'json', '--output', workDir];
    if (scope) jscpdCmd.push(scope);
    else jscpdCmd.push('provider-bw');
    if (args.jscpdArgs.length) jscpdCmd.push(...args.jscpdArgs);
    run(jscpdCmd[0], jscpdCmd.slice(1), { cwd: repoRoot });
    const jscpdReport = path.join(workDir, 'jscpd-report.json');
    if (existsSync(jscpdReport)) writeFileSync(jscpdOut, readFileSync(jscpdReport));

    // fallow: use repo-relative directory or full repo scan if no scope.
    const fallowCmd = ['fallow', 'dupes', '--format', 'json'];
    if (scope) fallowCmd.push(scope);
    if (args.fallowArgs.length) fallowCmd.push(...args.fallowArgs);
    const fallowJson = run(fallowCmd[0], fallowCmd.slice(1), { cwd: repoRoot });
    writeFileSync(fallowOut, fallowJson);

    const summary = `# Duplication audit summary\n\nScope: ${scope || 'repo-wide bw-react focus'}\n\nGenerated files:\n- ${path.relative(repoRoot, jscpdOut)}\n- ${path.relative(repoRoot, fallowOut)}\n\nNext step: run the Pi skill reasoning pass to compare both reports and curate meaningful refactors.\n`;
    writeFileSync(summaryOut, summary);
    console.log(summaryOut);
  } finally {
    rmSync(workDir, { recursive: true, force: true });
  }
}

main();

