import os from 'node:os';
import path from 'node:path';

const SUPPORTED_EXTENSIONS = new Set(['.js', '.jsx', '.ts', '.tsx', '.mjs', '.cjs', '.mts', '.cts']);
const ALWAYS_IGNORED_SEGMENTS = new Set([
  '.git',
  'node_modules',
  'dist',
  'build',
  'coverage',
  '.next',
  '.nx',
  'storybook-static',
  '__snapshots__',
  '__mocks__',
]);
const GENERATED_SEGMENTS = new Set(['generated', '__generated__']);

function printHelp() {
  console.log(`Combined bw-react duplication auditor for fallow + jscpd.

Usage:
  node .pi/skills/duplication-auditor/scripts/run-duplication-auditor.mjs [scope] [options]

Scope:
  - Optional repo-relative or absolute path
  - Must contain "bw-react"
  - Leading "@" is allowed and will be stripped
  - Example: provider-bw/libs/bw-react-cockpit/

Options:
  --scope <path>                 Explicit scope path
  --out-dir <path>               Output directory (default: docs/analysis)
  --include-tests                Include __tests__, *.test.*, *.spec.*
  --include-generated            Include generated / __generated__ files
  --no-ignore-imports            Do not pass --ignore-imports to fallow
  --fallow-mode <mode>           strict|mild|weak|semantic (default: semantic)
  --fallow-min-lines <number>    Fallow minimum duplicated lines (default: 8)
  --jscpd-min-lines <number>     JSCPD minimum duplicated lines (default: 8)
  --jscpd-min-tokens <number>    JSCPD minimum duplicated tokens (default: 50)
  --jscpd-mode <mode>            strict|mild|weak (default: mild)
  --top <number>                 Items to show in markdown summary sections (default: 15)
  --keep-temp                    Keep the filtered temporary workspace
  --quiet                        Reduce script logging
  --fallow-arg <value>           Extra raw arg for fallow (repeatable)
  --jscpd-arg <value>            Extra raw arg for jscpd (repeatable)
  -h, --help                     Show help

Examples:
  node .pi/skills/duplication-auditor/scripts/run-duplication-auditor.mjs
  node .pi/skills/duplication-auditor/scripts/run-duplication-auditor.mjs provider-bw/libs/bw-react-cockpit/
  node .pi/skills/duplication-auditor/scripts/run-duplication-auditor.mjs @provider-bw/libs/bw-react-marketplace/ --top 20
`);
}

function parseArgs(argv) {
  const options = {
    scope: null,
    outDir: 'docs/analysis',
    includeTests: false,
    includeGenerated: false,
    ignoreImports: true,
    fallowMode: 'semantic',
    fallowMinLines: '8',
    jscpdMinLines: '8',
    jscpdMinTokens: '50',
    jscpdMode: 'mild',
    top: 15,
    keepTemp: false,
    quiet: false,
    extraFallowArgs: [],
    extraJscpdArgs: [],
  };

  for (let index = 0; index < argv.length; index += 1) {
    const arg = argv[index];
    const next = argv[index + 1];

    switch (arg) {
      case '--scope':
        if (!next) throw new Error('--scope requires a value');
        options.scope = next;
        index += 1;
        break;
      case '--out-dir':
        if (!next) throw new Error('--out-dir requires a value');
        options.outDir = next;
        index += 1;
        break;
      case '--include-tests':
        options.includeTests = true;
        break;
      case '--include-generated':
        options.includeGenerated = true;
        break;
      case '--no-ignore-imports':
        options.ignoreImports = false;
        break;
      case '--fallow-mode':
        if (!next) throw new Error('--fallow-mode requires a value');
        options.fallowMode = next;
        index += 1;
        break;
      case '--fallow-min-lines':
        if (!next) throw new Error('--fallow-min-lines requires a value');
        options.fallowMinLines = next;
        index += 1;
        break;
      case '--jscpd-min-lines':
        if (!next) throw new Error('--jscpd-min-lines requires a value');
        options.jscpdMinLines = next;
        index += 1;
        break;
      case '--jscpd-min-tokens':
        if (!next) throw new Error('--jscpd-min-tokens requires a value');
        options.jscpdMinTokens = next;
        index += 1;
        break;
      case '--jscpd-mode':
        if (!next) throw new Error('--jscpd-mode requires a value');
        options.jscpdMode = next;
        index += 1;
        break;
      case '--top':
        if (!next) throw new Error('--top requires a value');
        options.top = Number.parseInt(next, 10);
        index += 1;
        break;
      case '--keep-temp':
        options.keepTemp = true;
        break;
      case '--quiet':
        options.quiet = true;
        break;
      case '--fallow-arg':
        if (!next) throw new Error('--fallow-arg requires a value');
        options.extraFallowArgs.push(next);
        index += 1;
        break;
      case '--jscpd-arg':
        if (!next) throw new Error('--jscpd-arg requires a value');
        options.extraJscpdArgs.push(next);
        index += 1;
        break;
      case '-h':
