  const parts = normalizeSlashes(relativePath).split('/');
  return parts.slice(0, -1).some((part) => part.includes('bw-react'));
}

function getBwReactRoot(relativePath) {
  const parts = normalizeSlashes(relativePath).split('/');
  const index = parts.findIndex((part) => part.includes('bw-react'));
  return index === -1 ? null : parts.slice(0, index + 1).join('/');
}

function matchesScope(relativePath, scope) {
  if (!scope) {
    return true;
  }

  return relativePath === scope || relativePath.startsWith(`${scope}/`);
}

function isGeneratedFile(fileName, parts) {
  return parts.some((part) => GENERATED_SEGMENTS.has(part)) || /(?:\.generated|\.gen)\.[^.]+$/i.test(fileName);
}

function isTestFile(fileName, parts) {
  return parts.includes('__tests__') || /\.(test|spec)\.[^.]+$/i.test(fileName);
}

function shouldIncludeFile(relativePath, options) {
  const normalizedPath = normalizeSlashes(relativePath);
  const parts = normalizedPath.split('/');
  const fileName = parts.at(-1) ?? '';
  const extension = path.extname(fileName).toLowerCase();

  if (!SUPPORTED_EXTENSIONS.has(extension)) {
    return false;
  }

  if (!isInsideBwReactFolder(normalizedPath)) {
    return false;
  }

