  }

  if (/\.(stories|story)\.[^.]+$/i.test(fileName)) {
    return false;
  }

  if (!options.includeGenerated && isGeneratedFile(fileName, parts)) {
    return false;
  }

  if (!options.includeTests && isTestFile(fileName, parts)) {
    return false;
  }

  return true;
}

async function copySelectedFiles(files, repoRoot, tempRoot) {
  for (const relativePath of files) {
    const sourcePath = path.resolve(repoRoot, relativePath);
    const destinationPath = path.join(tempRoot, relativePath);
    await mkdir(path.dirname(destinationPath), { recursive: true });
    await copyFile(sourcePath, destinationPath);
  }
}

