      const entry = fileStats.get(file) ?? createFileStatEntry(file);
      entry.fallowGroups += 1;
      entry.fallowDuplicatedLines += lineCount;
      fileStats.set(file, entry);
    }

    for (let i = 0; i < files.length; i += 1) {
      for (let j = i + 1; j < files.length; j += 1) {
