        entry.fallowDuplicatedLines += lineCount;
        entry.fallowMaxLines = Math.max(entry.fallowMaxLines, lineCount);
        pairStats.set(key, entry);
      }
    }
  }

  return {
    totalGroups: report.clone_groups?.length ?? 0,
    totalFamilies: report.clone_families?.length ?? 0,
    sameFileGroups,
    crossFileGroups,
    fileStats,
    pairStats,
    stats: report.stats ?? {},
  };
}

function parseJscpdReport(report) {
  const fileStats = new Map();
  const pairStats = new Map();
