#!/usr/bin/env node
import { execFileSync } from 'node:child_process';
import { existsSync, mkdirSync, rmSync, writeFileSync, readFileSync } from 'node:fs';
import path from 'node:path';
import os from 'node:os';

const DEFAULT_JSCPD_IGNORES = [
  '**/__tests__/**',
  '**/*.test.*',
  '**/*.spec.*',
  '**/*.story.*',
  '**/*.stories.*',
  '**/stories/**',
  '**/__snapshots__/**',
  '**/snapshots/**',
  '**/*.snap',
  '**/*.snapshot',
  '**/generated/**',
  '**/__generated__/**',
  '**/node_modules/**',
  '**/dist/**',
  '**/build/**',
  '**/coverage/**',
  '**/.next/**',
  '**/.nx/**',
  '**/storybook-static/**',
];

const DEFAULT_MIN_LINES = 8;
const DEFAULT_MIN_TOKENS = 80;

function parseArgs(argv) {
  const args = { scope: null, outDir: 'docs/analysis', jscpdArgs: [], fallowArgs: [] };
  const rest = [];
  let passthrough = false;
  for (let i = 0; i < argv.length; i++) {
    const a = argv[i];
    if (passthrough) {
      rest.push(a);
      continue;
    }
    if (a === '--') {
      passthrough = true;
      continue;
    }
    if (a === '--scope') {
      args.scope = argv[++i];
      continue;
    }
    if (a === '--out-dir') {
      args.outDir = argv[++i];
      continue;
    }
    if (a === '--jscpd-args') {
      args.jscpdArgs = argv[++i].split(' ').filter(Boolean);
      continue;
    }
    if (a === '--fallow-args') {
      args.fallowArgs = argv[++i].split(' ').filter(Boolean);
      continue;
    }
    if (!args.scope) args.scope = a;
    else rest.push(a);
  }
  args.passthrough = rest;
  return args;
}

function run(cmd, args, opts = {}) {
  return execFileSync(cmd, args, {
    encoding: 'utf8',
    stdio: ['ignore', 'pipe', 'pipe'],
    maxBuffer: 128 * 1024 * 1024,
    ...opts,
  });
}

function assertBwReactScope(scope) {
  if (scope && !scope.includes('bw-react')) {
    throw new Error(`Scope must contain "bw-react". Got: ${scope}`);
  }
}

function normalizeRelPath(relPath) {
  return relPath.replace(/\\/g, '/').replace(/\/+$/, '');
}

function pathParts(relPath) {
  return normalizeRelPath(relPath).split('/').filter(Boolean);
}

function isBwReactPath(relPath) {
  return pathParts(relPath).some((part) => part.includes('bw-react'));
}

function isDiscoveryNoise(relPath) {
  const noisySegments = new Set([
    'node_modules',
    'dist',
    'build',
    'coverage',
    '.next',
    '.nx',
    'storybook-static',
  ]);
  return pathParts(relPath).some((part) => noisySegments.has(part));
}

function isWithinScope(relPath, scopePath) {
  if (!scopePath) return true;
  const normalizedRel = normalizeRelPath(relPath);
  const normalizedScope = normalizeRelPath(scopePath);
  return normalizedRel === normalizedScope || normalizedRel.startsWith(`${normalizedScope}/`);
}

function findSrcRoot(relPath) {
  const parts = pathParts(relPath);
  const bwReactIndex = parts.findIndex((part) => part.includes('bw-react'));
  if (bwReactIndex === -1) return null;
  const srcIndex = parts.indexOf('src', bwReactIndex + 1);
  if (srcIndex === -1) return null;
  return parts.slice(0, srcIndex + 1).join('/');
}

function discoverJscpdTargets(repoRoot, scope) {
  const scopePath = scope ? normalizeRelPath(path.relative(repoRoot, path.resolve(repoRoot, scope))) : null;
  const fileList = run('git', ['ls-files', '-co', '--exclude-standard'], { cwd: repoRoot })
    .split('\n')
    .map((line) => normalizeRelPath(line.trim()))
    .filter(Boolean);

  const targets = new Map();
  let fallbackUsed = false;
  let fallbackReason = '';

  for (const relPath of fileList) {
    if (!isWithinScope(relPath, scopePath)) {
      continue;
    }
    if (!isBwReactPath(relPath) || isDiscoveryNoise(relPath)) {
      continue;
    }

    const srcRoot = findSrcRoot(relPath);
    if (srcRoot) {
      targets.set(srcRoot, {
        path: srcRoot,
        reason: `derived from ${relPath}`,
      });
    }
  }

  if (targets.size === 0) {
    fallbackUsed = true;
    if (scopePath) {
      const fallbackTarget = scopePath;
      targets.set(fallbackTarget, {
        path: fallbackTarget,
        reason: 'fallback to requested scope path because no bw-react src child was found',
      });
      fallbackReason = 'No bw-react src directory was found beneath the requested scope, so the scope path itself was scanned.';
    } else {
      for (const relPath of fileList) {
        if (!isBwReactPath(relPath) || isDiscoveryNoise(relPath)) {
          continue;
        }
        const srcRoot = findSrcRoot(relPath);
        if (srcRoot) {
          targets.set(srcRoot, {
            path: srcRoot,
            reason: `derived from ${relPath}`,
          });
        }
      }

      if (targets.size === 0) {
        targets.set('provider-bw', {
          path: 'provider-bw',
          reason: 'last-resort fallback because no bw-react src directories were discovered',
        });
        fallbackReason = 'No bw-react src directories were discovered, so provider-bw was used as a last resort.';
      } else {
        fallbackReason = 'Repo-wide discovery found no direct src children at the initial pass, so all discovered bw-react src roots were used.';
      }
    }
  }

  return {
    scopePath,
    requestedScope: scope || 'bw-react',
    targets: [...targets.values()].sort((a, b) => a.path.localeCompare(b.path)),
    fallbackUsed,
    fallbackReason,
    defaults: {
      minLines: DEFAULT_MIN_LINES,
      minTokens: DEFAULT_MIN_TOKENS,
      ignores: DEFAULT_JSCPD_IGNORES,
    },
  };
}

function main() {
  const args = parseArgs(process.argv.slice(2));
  const scope = args.scope || '';
  assertBwReactScope(scope || 'bw-react');

  const repoRoot = run('git', ['rev-parse', '--show-toplevel']).trim();
  const tmpRoot = path.join(os.tmpdir(), 'pi-duplication-auditor');
  mkdirSync(tmpRoot, { recursive: true });
  const workDir = path.join(tmpRoot, String(Date.now()));
  mkdirSync(workDir, { recursive: true });
  const outDir = path.resolve(repoRoot, args.outDir);
  mkdirSync(outDir, { recursive: true });

  const scopeArg = scope || 'bw-react';
  const scopeLabel = scopeArg.replace(/[^a-zA-Z0-9._-]+/g, '_');
  const jscpdOut = path.join(outDir, `jscpd-${scopeLabel}.json`);
  const fallowOut = path.join(outDir, `fallow-${scopeLabel}.json`);
  const summaryOut = path.join(outDir, `duplication-summary-${scopeLabel}.md`);
  const scanPlan = discoverJscpdTargets(repoRoot, scope);

  try {
    const jscpdCmd = ['jscpd', '--reporters', 'json', '--output', workDir, '--min-lines', String(DEFAULT_MIN_LINES), '--min-tokens', String(DEFAULT_MIN_TOKENS)];
    for (const ignoreGlob of DEFAULT_JSCPD_IGNORES) {
      jscpdCmd.push('--ignore', ignoreGlob);
    }
    jscpdCmd.push(...scanPlan.targets.map((target) => target.path));
    if (args.jscpdArgs.length) jscpdCmd.push(...args.jscpdArgs);
    if (args.passthrough.length) jscpdCmd.push(...args.passthrough);

    run(jscpdCmd[0], jscpdCmd.slice(1), { cwd: repoRoot });
    const jscpdReport = path.join(workDir, 'jscpd-report.json');
    if (existsSync(jscpdReport)) writeFileSync(jscpdOut, readFileSync(jscpdReport));

    const fallowCmd = ['fallow', 'dupes', '--format', 'json'];
    if (scope) fallowCmd.push(scope);
    if (args.fallowArgs.length) fallowCmd.push(...args.fallowArgs);
    const fallowJson = run(fallowCmd[0], fallowCmd.slice(1), { cwd: repoRoot });
    writeFileSync(fallowOut, fallowJson);

    const summary = `# Duplication audit summary

## Scope
- Requested scope: \`${scanPlan.requestedScope}\`
- Effective scope: bw-react \`src\` roots derived from the requested scope when available
- Effective jscpd targets:
${scanPlan.targets.map((target) => `  - \`${target.path}\` (${target.reason})`).join('\n')}
- Fallback used: ${scanPlan.fallbackUsed ? 'yes' : 'no'}${scanPlan.fallbackUsed && scanPlan.fallbackReason ? `\n- Fallback note: ${scanPlan.fallbackReason}` : ''}

## jscpd defaults
- min-lines: \`${scanPlan.defaults.minLines}\`
- min-tokens: \`${scanPlan.defaults.minTokens}\`
- ignore globs:
${scanPlan.defaults.ignores.map((glob) => `  - \`${glob}\``).join('\n')}
- extra jscpd args: ${args.jscpdArgs.length ? `\`${args.jscpdArgs.join(' ')}\`` : '(none)'}
- passthrough args (applied to jscpd only): ${args.passthrough.length ? `\`${args.passthrough.join(' ')}\`` : '(none)'}

## fallow notes
- Requested fallow scope: ${scope ? `\`${scope}\`` : '(repo root default)'}
- extra fallow args: ${args.fallowArgs.length ? `\`${args.fallowArgs.join(' ')}\`` : '(none)'}
- comparison caveat: fallow is invoked on the requested scope string, while jscpd is narrowed to bw-react src roots. Until the helper aligns both tools further, expect fallow to report a broader/noisier surface area than jscpd.

## Generated files
- ${path.relative(repoRoot, jscpdOut)}
- ${path.relative(repoRoot, fallowOut)}

Next step: run the Pi skill reasoning pass to compare both reports and curate meaningful refactors.
`;
    writeFileSync(summaryOut, summary);
    console.log(summaryOut);
  } finally {
    rmSync(workDir, { recursive: true, force: true });
  }
}

main();

